export const ARTICLES_08: Article[] = [
  { id: 'ccyc-art-901', lawId: 'codigo-civil-comercial', number: '901', order: 901, title: "Imputación por el acreedor", text: "Imputación por el acreedor. Si el deudor no imputa el pago, el acreedor se encuentra facultado a hacerlo en el momento de recibirlo, conforme a estas reglas: a) debe imputarlo a alguna de las deudas líquidas y exigibles; b) una vez canceladas totalmente una o varias deudas, puede aplicar el saldo a la cancelación parcial de cualquiera de las otras.", plainLanguageExplanation: "Establece el régimen de imputación por el acreedor. Si el deudor no imputa el pago, el acreedor se encuentra facultado a hacerlo en el momento de recibirlo, conforme a estas reglas: a) debe imputarlo a alguna de las deudas líquidas y exigibles; b) una vez canceladas totalmente una o varias deudas, puede aplicar el saldo a la cance", practicalEffects: ['En la práctica, este artículo rige imputación por el acreedor. Si el deudor no imputa el pago, el acreedor se encuentra facultado a hacerlo en el momento de recibirlo, conforme a estas reglas: a) debe imputarlo a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['imputacin', 'acreedor', 'articulo 901'], segments: [], amendments: [] },
  { id: 'ccyc-art-902', lawId: 'codigo-civil-comercial', number: '902', order: 902, title: "Imputación legal", text: "Imputación legal. Si el deudor o el acreedor no hacen imputación del pago, se lo imputa: a) en primer término, a la obligación de plazo vencido más onerosa para el deudor; b) cuando las deudas son igualmente onerosas, el pago se imputa a prorrata.", plainLanguageExplanation: "Establece el régimen de imputación legal. Si el deudor o el acreedor no hacen imputación del pago, se lo imputa: a) en primer término, a la obligación de plazo vencido más onerosa para el deudor; b) cuando las deudas son igualmente onerosas, el pago se imputa a prorrata.", practicalEffects: ['En la práctica, este artículo rige imputación legal. Si el deudor o el acreedor no hacen imputación del pago, se lo imputa: a) en primer término, a la obligación de plazo vencido más onerosa para el deud'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['imputacin', 'legal', 'articulo 902'], segments: [], amendments: [] },
  { id: 'ccyc-art-903', lawId: 'codigo-civil-comercial', number: '903', order: 903, title: "Pago a cuenta de capital e intereses", text: "Pago a cuenta de capital e intereses. Si el pago se hace a cuenta de capital e intereses y no se precisa su orden, se imputa en primer término a intereses, a no ser que el acreedor dé recibo por cuenta de capital. SECCION 7ª Pago por consignación Parágrafo 1° Consignación judicial", plainLanguageExplanation: "Establece el régimen de pago a cuenta de capital e intereses. Si el pago se hace a cuenta de capital e intereses y no se precisa su orden, se imputa en primer término a intereses, a no ser que el acreedor dé recibo por cuenta de capital.", practicalEffects: ['En la práctica, este artículo rige pago a cuenta de capital e intereses. Si el pago se hace a cuenta de capital e intereses y no se precisa su orden, se imputa en primer término a intereses, a no ser que el acreedor dé recibo por cuenta de capital.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pago', 'cuenta', 'capital', 'intereses', 'articulo 903'], segments: [], amendments: [] },
  { id: 'ccyc-art-904', lawId: 'codigo-civil-comercial', number: '904', order: 904, title: "Casos en que procede", text: "Casos en que procede. El pago por consignación procede cuando: a) el acreedor fue constituido en mora; b) existe incertidumbre sobre la persona del acreedor; c) el deudor no puede realizar un pago seguro y válido por causa que no le es imputable.", plainLanguageExplanation: "Establece el régimen de casos en que procede. El pago por consignación procede cuando: a) el acreedor fue constituido en mora; b) existe incertidumbre sobre la persona del acreedor; c) el deudor no puede realizar un pago seguro y válido por causa que no le es imputable.", practicalEffects: ['En la práctica, este artículo rige casos en que procede. El pago por consignación procede cuando: a) el acreedor fue constituido en mora; b) existe incertidumbre sobre la persona del acreedor; c) el deudor n'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'procede', 'articulo 904'], segments: [], amendments: [] },
  { id: 'ccyc-art-905', lawId: 'codigo-civil-comercial', number: '905', order: 905, title: "Requisitos", text: "Requisitos. El pago por consignación está sujeto a los mismos requisitos del pago.", plainLanguageExplanation: "Establece el régimen de requisitos. El pago por consignación está sujeto a los mismos requisitos del pago.", practicalEffects: ['En la práctica, este artículo rige requisitos. El pago por consignación está sujeto a los mismos requisitos del pago.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 905'], segments: [], amendments: [] },
  { id: 'ccyc-art-906', lawId: 'codigo-civil-comercial', number: '906', order: 906, title: "Forma", text: "Forma. El pago por consignación se rige por las siguientes reglas: a) si la prestación consiste en una suma de dinero, se requiere su depósito a la orden del juez interviniente, en el banco que dispongan las normas procesales; b) si se debe una cosa indeterminada a elección del acreedor y éste es moroso en practicar la elección, una vez vencido el término del emplazamiento judicial hecho al acreedor, el juez autoriza al deudor a realizarla; c) si las cosas debidas no pueden ser conservadas o su custodia origina gastos excesivos, el juez puede autorizar la venta en subasta, y ordenar el depósito del precio que se obtenga.", plainLanguageExplanation: "Establece el régimen de forma. El pago por consignación se rige por las siguientes reglas: a) si la prestación consiste en una suma de dinero, se requiere su depósito a la orden del juez interviniente, en el banco que dispongan las normas procesales; b) si se debe una cosa indeterminada a elección del acreedor", practicalEffects: ['En la práctica, este artículo rige forma. El pago por consignación se rige por las siguientes reglas: a) si la prestación consiste en una suma de dinero, se requiere su depósito a la orden del'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formaarticulo 906'], segments: [], amendments: [] },
  { id: 'ccyc-art-907', lawId: 'codigo-civil-comercial', number: '907', order: 907, title: "Efectos", text: "Efectos. La consignación judicial, no impugnada por el acreedor, o declarada válida por reunir los requisitos del pago, extingue la deuda desde el día en que se notifica la demanda. Si la consignación es defectuosa, y el deudor subsana ulteriormente sus defectos, la extinción de la deuda se produce desde la fecha de notificación de la sentencia que la admite.", plainLanguageExplanation: "Establece el régimen de efectos. La consignación judicial, no impugnada por el acreedor, o declarada válida por reunir los requisitos del pago, extingue la deuda desde el día en que se notifica la demanda.", practicalEffects: ['En la práctica, este artículo rige efectos. La consignación judicial, no impugnada por el acreedor, o declarada válida por reunir los requisitos del pago, extingue la deuda desde el día en que se notifica la demanda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 907'], segments: [], amendments: [] },
  { id: 'ccyc-art-908', lawId: 'codigo-civil-comercial', number: '908', order: 908, title: "Deudor moroso", text: "Deudor moroso. El deudor moroso puede consignar la prestación debida con los accesorios devengados hasta el día de la consignación.", plainLanguageExplanation: "Establece el régimen de deudor moroso. El deudor moroso puede consignar la prestación debida con los accesorios devengados hasta el día de la consignación.", practicalEffects: ['En la práctica, este artículo rige deudor moroso. El deudor moroso puede consignar la prestación debida con los accesorios devengados hasta el día de la consignación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deudor', 'moroso', 'articulo 908'], segments: [], amendments: [] },
  { id: 'ccyc-art-909', lawId: 'codigo-civil-comercial', number: '909', order: 909, title: "Desistimiento", text: "Desistimiento. El deudor tiene derecho a desistir de la consignación antes de que la acepte el acreedor o de que haya sido declarada válida. Con posterioridad sólo puede desistir con la conformidad expresa del acreedor, quien en ese caso pierde la acción contra los codeudores, los garantes y los fiadores. Parágrafo 2° Consignación extrajudicial", plainLanguageExplanation: "Establece el régimen de desistimiento. El deudor tiene derecho a desistir de la consignación antes de que la acepte el acreedor o de que haya sido declarada válida.", practicalEffects: ['En la práctica, este artículo rige desistimiento. El deudor tiene derecho a desistir de la consignación antes de que la acepte el acreedor o de que haya sido declarada válida.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['desistimientoarticulo 909'], segments: [], amendments: [] },
  { id: 'ccyc-art-910', lawId: 'codigo-civil-comercial', number: '910', order: 910, title: "Procedencia y trámite", text: "Procedencia y trámite. Sin perjuicio de las disposiciones del Parágrafo 1°, el deudor de una suma de dinero puede optar por el trámite de consignación extrajudicial. A tal fin, debe depositar la suma adeudada ante un escribano de registro, a nombre y a disposición del acreedor, cumpliendo los siguientes recaudos: a) notificar previamente al acreedor, en forma fehaciente, del día, la hora y el lugar en que será efectuado el depósito; b) efectuar el depósito de la suma debida con más los intereses devengados hasta el día del depósito; este depósito debe ser notificado fehacientemente al acreedor por el escribano dentro de las cuarenta y ocho horas hábiles de realizado; si es imposible practicar la notificación, el deudor debe consignar judicialmente.", plainLanguageExplanation: "Establece el régimen de procedencia y trámite. Sin perjuicio de las disposiciones del Parágrafo 1°, el deudor de una suma de dinero puede optar por el trámite de consignación extrajudicial.", practicalEffects: ['En la práctica, este artículo rige procedencia y trámite. Sin perjuicio de las disposiciones del Parágrafo 1°, el deudor de una suma de dinero puede optar por el trámite de consignación extrajudicial.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['procedencia', 'trmite', 'articulo 910'], segments: [], amendments: [] },
  { id: 'ccyc-art-911', lawId: 'codigo-civil-comercial', number: '911', order: 911, title: "Derechos del acreedor", text: "Derechos del acreedor. Una vez notificado del depósito, dentro del quinto día hábil de notificado, el acreedor tiene derecho a: a) aceptar el procedimiento y retirar el depósito, estando a cargo del deudor el pago de los gastos y honorarios del escribano; b) rechazar el procedimiento y retirar el depósito, estando a cargo del acreedor el pago de los gastos y honorarios del escribano; c) rechazar el procedimiento y el depósito, o no expedirse. En ambos casos el deudor puede disponer de la suma depositada para consignarla judicialmente.", plainLanguageExplanation: "Establece el régimen de derechos del acreedor. Una vez notificado del depósito, dentro del quinto día hábil de notificado, el acreedor tiene derecho a: a) aceptar el procedimiento y retirar el depósito, estando a cargo del deudor el pago de los gastos y honorarios del escribano; b) rechazar el procedimiento y retirar el depós", practicalEffects: ['En la práctica, este artículo rige derechos del acreedor. Una vez notificado del depósito, dentro del quinto día hábil de notificado, el acreedor tiene derecho a: a) aceptar el procedimiento y retirar el depó'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'acreedor', 'articulo 911'], segments: [], amendments: [] },
  { id: 'ccyc-art-912', lawId: 'codigo-civil-comercial', number: '912', order: 912, title: "Derechos del acreedor que retira el depósito", text: "Derechos del acreedor que retira el depósito. Si el acreedor retira lo depositado y rechaza el pago, puede reclamar judicialmente un importe mayor o considerarlo insuficiente o exigir la repetición de lo pagado por gastos y honorarios por considerar que no se encontraba en mora, o ambas cosas. En el recibo debe hacer reserva de su derecho, caso contrario se considera que el pago es liberatorio desde el día del depósito. Para demandar tiene un término de caducidad de treinta días computados a partir del recibo con reserva.", plainLanguageExplanation: "Establece el régimen de derechos del acreedor que retira el depósito. Si el acreedor retira lo depositado y rechaza el pago, puede reclamar judicialmente un importe mayor o considerarlo insuficiente o exigir la repetición de lo pagado por gastos y honorarios por considerar que no se encontraba en mora, o ambas cosas.", practicalEffects: ['En la práctica, este artículo rige derechos del acreedor que retira el depósito. Si el acreedor retira lo depositado y rechaza el pago, puede reclamar judicialmente un importe mayor o considerarlo insuficiente o exigir la repetició'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'acreedor', 'retira', 'depsito', 'articulo 912'], segments: [], amendments: [] },
  { id: 'ccyc-art-913', lawId: 'codigo-civil-comercial', number: '913', order: 913, title: "Impedimentos", text: "Impedimentos. No se puede acudir al procedimiento previsto en este Parágrafo si antes del depósito, el acreedor optó por la resolución del contrato o demandó el cumplimiento de la obligación. SECCION 8ª Pago por subrogación", plainLanguageExplanation: "Establece el régimen de impedimentos. No se puede acudir al procedimiento previsto en este Parágrafo si antes del depósito, el acreedor optó por la resolución del contrato o demandó el cumplimiento de la obligación.", practicalEffects: ['En la práctica, este artículo rige impedimentos. No se puede acudir al procedimiento previsto en este Parágrafo si antes del depósito, el acreedor optó por la resolución del contrato o demandó el cumplimiento de la obligación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['impedimentosarticulo 913'], segments: [], amendments: [] },
  { id: 'ccyc-art-914', lawId: 'codigo-civil-comercial', number: '914', order: 914, title: "Pago por subrogación", text: "Pago por subrogación. El pago por subrogación transmite al tercero que paga todos los derechos y acciones del acreedor. La subrogación puede ser legal o convencional.", plainLanguageExplanation: "Establece el régimen de pago por subrogación. El pago por subrogación transmite al tercero que paga todos los derechos y acciones del acreedor.", practicalEffects: ['En la práctica, este artículo rige pago por subrogación. El pago por subrogación transmite al tercero que paga todos los derechos y acciones del acreedor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pago', 'subrogacin', 'articulo 914'], segments: [], amendments: [] },
  { id: 'ccyc-art-915', lawId: 'codigo-civil-comercial', number: '915', order: 915, title: "Subrogación legal", text: "Subrogación legal. La subrogación legal tiene lugar a favor: a) del que paga una deuda a la que estaba obligado con otros, o por otros; b) del tercero, interesado o no, que paga con asentimiento del deudor o en su ignorancia; c) del tercero interesado que paga aun con la oposición del deudor; d) del heredero con responsabilidad limitada que paga con fondos propios una deuda del causante.", plainLanguageExplanation: "Establece el régimen de subrogación legal. La subrogación legal tiene lugar a favor: a) del que paga una deuda a la que estaba obligado con otros, o por otros; b) del tercero, interesado o no, que paga con asentimiento del deudor o en su ignorancia; c) del tercero interesado que paga aun con la oposición del deudor; d) de", practicalEffects: ['En la práctica, este artículo rige subrogación legal. La subrogación legal tiene lugar a favor: a) del que paga una deuda a la que estaba obligado con otros, o por otros; b) del tercero, interesado o no,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['subrogacin', 'legal', 'articulo 915'], segments: [], amendments: [] },
  { id: 'ccyc-art-916', lawId: 'codigo-civil-comercial', number: '916', order: 916, title: "Subrogación convencional por el acreedor", text: "Subrogación convencional por el acreedor. El acreedor puede subrogar en sus derechos al tercero que paga.", plainLanguageExplanation: "Establece el régimen de subrogación convencional por el acreedor. El acreedor puede subrogar en sus derechos al tercero que paga.", practicalEffects: ['En la práctica, este artículo rige subrogación convencional por el acreedor. El acreedor puede subrogar en sus derechos al tercero que paga.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['subrogacin', 'convencional', 'acreedor', 'articulo 916'], segments: [], amendments: [] },
  { id: 'ccyc-art-917', lawId: 'codigo-civil-comercial', number: '917', order: 917, title: "Subrogación convencional por el deudor", text: "Subrogación convencional por el deudor. El deudor que paga al acreedor con fondos de terceros puede subrogar al prestamista. Para que tenga los efectos previstos en estas normas es necesario que: a) tanto el préstamo como el pago consten en instrumentos con fecha cierta anterior; b) en el recibo conste que los fondos pertenecen al subrogado; c) en el instrumento del préstamo conste que con ese dinero se cumplirá la obligación del deudor.", plainLanguageExplanation: "Establece el régimen de subrogación convencional por el deudor. El deudor que paga al acreedor con fondos de terceros puede subrogar al prestamista.", practicalEffects: ['En la práctica, este artículo rige subrogación convencional por el deudor. El deudor que paga al acreedor con fondos de terceros puede subrogar al prestamista.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['subrogacin', 'convencional', 'deudor', 'articulo 917'], segments: [], amendments: [] },
  { id: 'ccyc-art-918', lawId: 'codigo-civil-comercial', number: '918', order: 918, title: "Efectos", text: "Efectos. El pago por subrogación transmite al tercero todos los derechos y acciones del acreedor, y los accesorios del crédito. El tercero subrogante mantiene las acciones contra los coobligados, fiadores, y garantes personales y reales, y los privilegios y el derecho de retención si lo hay.", plainLanguageExplanation: "Establece el régimen de efectos. El pago por subrogación transmite al tercero todos los derechos y acciones del acreedor, y los accesorios del crédito.", practicalEffects: ['En la práctica, este artículo rige efectos. El pago por subrogación transmite al tercero todos los derechos y acciones del acreedor, y los accesorios del crédito.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 918'], segments: [], amendments: [] },
  { id: 'ccyc-art-919', lawId: 'codigo-civil-comercial', number: '919', order: 919, title: "Límites", text: "Límites. La transmisión del crédito tiene las siguientes limitaciones: a) el subrogado sólo puede ejercer el derecho transferido hasta el valor de lo pagado; b) el codeudor de una obligación de sujeto plural solamente puede reclamar a los demás codeudores la parte que a cada uno de ellos les corresponde cumplir; c) la subrogación convencional puede quedar limitada a ciertos derechos o acciones.", plainLanguageExplanation: "Establece el régimen de límites. La transmisión del crédito tiene las siguientes limitaciones: a) el subrogado sólo puede ejercer el derecho transferido hasta el valor de lo pagado; b) el codeudor de una obligación de sujeto plural solamente puede reclamar a los demás codeudores la parte que a cada uno de ellos", practicalEffects: ['En la práctica, este artículo rige límites. La transmisión del crédito tiene las siguientes limitaciones: a) el subrogado sólo puede ejercer el derecho transferido hasta el valor de lo pagado; b'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['lmitesarticulo 919'], segments: [], amendments: [] },
  { id: 'ccyc-art-920', lawId: 'codigo-civil-comercial', number: '920', order: 920, title: "Subrogación parcial", text: "Subrogación parcial. Si el pago es parcial, el tercero y el acreedor concurren frente al deudor de manera proporcional. CAPITULO 5 Otros modos de extinción SECCION 1ª Compensación", plainLanguageExplanation: "Establece el régimen de subrogación parcial. Si el pago es parcial, el tercero y el acreedor concurren frente al deudor de manera proporcional.", practicalEffects: ['En la práctica, este artículo rige subrogación parcial. Si el pago es parcial, el tercero y el acreedor concurren frente al deudor de manera proporcional.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['subrogacin', 'parcial', 'articulo 920'], segments: [], amendments: [] },
  { id: 'ccyc-art-921', lawId: 'codigo-civil-comercial', number: '921', order: 921, title: "Definición", text: "Definición. La compensación de las obligaciones tiene lugar cuando dos personas, por derecho propio, reúnen la calidad de acreedor y deudor recíprocamente, cualesquiera que sean las causas de una y otra deuda. Extingue con fuerza de pago las dos deudas, hasta el monto de la menor, desde el tiempo en que ambas obligaciones comenzaron a coexistir en condiciones de ser compensables.", plainLanguageExplanation: "Establece el régimen de definición. La compensación de las obligaciones tiene lugar cuando dos personas, por derecho propio, reúnen la calidad de acreedor y deudor recíprocamente, cualesquiera que sean las causas de una y otra deuda.", practicalEffects: ['En la práctica, este artículo rige definición. La compensación de las obligaciones tiene lugar cuando dos personas, por derecho propio, reúnen la calidad de acreedor y deudor recíprocamente, cualesquiera que sean las causas de una y otra deuda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 921'], segments: [], amendments: [] },
  { id: 'ccyc-art-922', lawId: 'codigo-civil-comercial', number: '922', order: 922, title: "Especies", text: "Especies. La compensación puede ser legal, convencional, facultativa o judicial.", plainLanguageExplanation: "Establece el régimen de especies. La compensación puede ser legal, convencional, facultativa o judicial.", practicalEffects: ['En la práctica, este artículo rige especies. La compensación puede ser legal, convencional, facultativa o judicial.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['especiesarticulo 922'], segments: [], amendments: [] },
  { id: 'ccyc-art-923', lawId: 'codigo-civil-comercial', number: '923', order: 923, title: "Requisitos de la compensación legal", text: "Requisitos de la compensación legal. Para que haya compensación legal: a) ambas partes deben ser deudoras de prestaciones de dar; b) los objetos comprendidos en las prestaciones deben ser homogéneos entre sí; c) los créditos deben ser exigibles y disponibles libremente, sin que resulte afectado el derecho de terceros.", plainLanguageExplanation: "Establece el régimen de requisitos de la compensación legal. Para que haya compensación legal: a) ambas partes deben ser deudoras de prestaciones de dar; b) los objetos comprendidos en las prestaciones deben ser homogéneos entre sí; c) los créditos deben ser exigibles y disponibles libremente, sin que resulte afectado el derecho de tercero", practicalEffects: ['En la práctica, este artículo rige requisitos de la compensación legal. Para que haya compensación legal: a) ambas partes deben ser deudoras de prestaciones de dar; b) los objetos comprendidos en las prestaciones deben ser'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos', 'compensacin', 'legal', 'articulo 923'], segments: [], amendments: [] },
  { id: 'ccyc-art-924', lawId: 'codigo-civil-comercial', number: '924', order: 924, title: "Efectos", text: "Efectos. Una vez opuesta, la compensación legal produce sus efectos a partir del momento en que ambas deudas reciprocas coexisten en condiciones de ser compensadas, aunque el crédito no sea líquido o sea impugnado por el deudor.", plainLanguageExplanation: "Establece el régimen de efectos. Una vez opuesta, la compensación legal produce sus efectos a partir del momento en que ambas deudas reciprocas coexisten en condiciones de ser compensadas, aunque el crédito no sea líquido o sea impugnado por el deudor.", practicalEffects: ['En la práctica, este artículo rige efectos. Una vez opuesta, la compensación legal produce sus efectos a partir del momento en que ambas deudas reciprocas coexisten en condiciones de ser compens'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 924'], segments: [], amendments: [] },
  { id: 'ccyc-art-925', lawId: 'codigo-civil-comercial', number: '925', order: 925, title: "Fianza", text: "Fianza. El fiador puede oponer la compensación de lo que el acreedor le deba a él o al deudor principal. Pero éste no puede oponer al acreedor la compensación de su deuda con la deuda del acreedor al fiador.", plainLanguageExplanation: "Establece el régimen de fianza. El fiador puede oponer la compensación de lo que el acreedor le deba a él o al deudor principal.", practicalEffects: ['En la práctica, este artículo rige fianza. El fiador puede oponer la compensación de lo que el acreedor le deba a él o al deudor principal.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fianzaarticulo 925'], segments: [], amendments: [] },
  { id: 'ccyc-art-926', lawId: 'codigo-civil-comercial', number: '926', order: 926, title: "Pluralidad de deudas del mismo deudor", text: "Pluralidad de deudas del mismo deudor. Si el deudor tiene varias deudas compensables con el mismo acreedor, se aplican las reglas de la imputación del pago.", plainLanguageExplanation: "Establece el régimen de pluralidad de deudas del mismo deudor. Si el deudor tiene varias deudas compensables con el mismo acreedor, se aplican las reglas de la imputación del pago.", practicalEffects: ['En la práctica, este artículo rige pluralidad de deudas del mismo deudor. Si el deudor tiene varias deudas compensables con el mismo acreedor, se aplican las reglas de la imputación del pago.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pluralidad', 'deudas', 'mismo', 'deudor', 'articulo 926'], segments: [], amendments: [] },
  { id: 'ccyc-art-927', lawId: 'codigo-civil-comercial', number: '927', order: 927, title: "Compensación facultativa", text: "Compensación facultativa. La compensación facultativa actúa por la voluntad de una sola de las partes cuando ella renuncia a un requisito faltante para la compensación legal que juega a favor suyo. Produce sus efectos desde el momento en que es comunicada a la otra parte.", plainLanguageExplanation: "Establece el régimen de compensación facultativa. La compensación facultativa actúa por la voluntad de una sola de las partes cuando ella renuncia a un requisito faltante para la compensación legal que juega a favor suyo.", practicalEffects: ['En la práctica, este artículo rige compensación facultativa. La compensación facultativa actúa por la voluntad de una sola de las partes cuando ella renuncia a un requisito faltante para la compensación legal que juega a favor suyo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['compensacin', 'facultativa', 'articulo 927'], segments: [], amendments: [] },
  { id: 'ccyc-art-928', lawId: 'codigo-civil-comercial', number: '928', order: 928, title: "Compensación judicial", text: "Compensación judicial. Cualquiera de las partes tiene derecho a requerir a un juez la declaración de la compensación que se ha producido. La pretensión puede ser deducida simultáneamente con las defensas relativas al crédito de la otra parte o, subsidiariamente, para el caso de que esas defensas no prosperen.", plainLanguageExplanation: "Establece el régimen de compensación judicial. Cualquiera de las partes tiene derecho a requerir a un juez la declaración de la compensación que se ha producido.", practicalEffects: ['En la práctica, este artículo rige compensación judicial. Cualquiera de las partes tiene derecho a requerir a un juez la declaración de la compensación que se ha producido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['compensacin', 'judicial', 'articulo 928'], segments: [], amendments: [] },
  { id: 'ccyc-art-929', lawId: 'codigo-civil-comercial', number: '929', order: 929, title: "Exclusión convencional", text: "Exclusión convencional. La compensación puede ser excluida convencionalmente.", plainLanguageExplanation: "Establece el régimen de exclusión convencional. La compensación puede ser excluida convencionalmente.", practicalEffects: ['En la práctica, este artículo rige exclusión convencional. La compensación puede ser excluida convencionalmente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['exclusin', 'convencional', 'articulo 929'], segments: [], amendments: [] },
  { id: 'ccyc-art-930', lawId: 'codigo-civil-comercial', number: '930', order: 930, title: "Obligaciones no compensables", text: "Obligaciones no compensables. No son compensables: a) las deudas por alimentos; b) las obligaciones de hacer o no hacer; c) la obligación de pagar daños e intereses por no poderse restituir la cosa de que el propietario o poseedor legítimo fue despojado; d) las deudas que el legatario tenga con el causante si los bienes de la herencia son insuficientes para satisfacer las obligaciones y los legados restantes; e) las deudas y créditos entre los particulares y el Estado nacional, provincial o municipal, cuando: i) las deudas de los particulares provienen del remate de bienes pertenecientes a la Nación, provincia o municipio; de rentas fiscales, contribuciones directas o indirectas o de otros pagos que deben efectuarse en las aduanas, como los derechos de almacenaje o depósito; ii) las deudas y créditos pertenecen a distintos ministerios o departamentos; iii) los créditos de los particulares se hallan comprendidos en la consolidación de acreencias contra el Estado dispuesta por ley. f) los créditos y las deudas en el concurso y quiebra, excepto en los alcances en que lo prevé la ley especial; g) la deuda del obligado a restituir un depósito irregular. SECCION 2ª Confusión", plainLanguageExplanation: "Establece el régimen de obligaciones no compensables. No son compensables: a) las deudas por alimentos; b) las obligaciones de hacer o no hacer; c) la obligación de pagar daños e intereses por no poderse restituir la cosa de que el propietario o poseedor legítimo fue despojado; d) las deudas que el legatario tenga con el causante si", practicalEffects: ['En la práctica, este artículo rige obligaciones no compensables. No son compensables: a) las deudas por alimentos; b) las obligaciones de hacer o no hacer; c) la obligación de pagar daños e intereses por no poderse'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'compensables', 'articulo 930'], segments: [], amendments: [] },
  { id: 'ccyc-art-931', lawId: 'codigo-civil-comercial', number: '931', order: 931, title: "Definición", text: "Definición. La obligación se extingue por confusión cuando las calidades de acreedor y de deudor se reúnen en una misma persona y en un mismo patrimonio.", plainLanguageExplanation: "Establece el régimen de definición. La obligación se extingue por confusión cuando las calidades de acreedor y de deudor se reúnen en una misma persona y en un mismo patrimonio.", practicalEffects: ['En la práctica, este artículo rige definición. La obligación se extingue por confusión cuando las calidades de acreedor y de deudor se reúnen en una misma persona y en un mismo patrimonio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 931'], segments: [], amendments: [] },
  { id: 'ccyc-art-932', lawId: 'codigo-civil-comercial', number: '932', order: 932, title: "Efectos", text: "Efectos. La obligación queda extinguida, total o parcialmente, en proporción a la parte de la deuda en que se produce la confusión. SECCION 3ª Novación", plainLanguageExplanation: "Establece el régimen de efectos. La obligación queda extinguida, total o parcialmente, en proporción a la parte de la deuda en que se produce la confusión.", practicalEffects: ['En la práctica, este artículo rige efectos. La obligación queda extinguida, total o parcialmente, en proporción a la parte de la deuda en que se produce la confusión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 932'], segments: [], amendments: [] },
  { id: 'ccyc-art-933', lawId: 'codigo-civil-comercial', number: '933', order: 933, title: "Definición", text: "Definición. La novación es la extinción de una obligación por la creación de otra nueva, destinada a reemplazarla.", plainLanguageExplanation: "Establece el régimen de definición. La novación es la extinción de una obligación por la creación de otra nueva, destinada a reemplazarla.", practicalEffects: ['En la práctica, este artículo rige definición. La novación es la extinción de una obligación por la creación de otra nueva, destinada a reemplazarla.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 933'], segments: [], amendments: [] },
  { id: 'ccyc-art-934', lawId: 'codigo-civil-comercial', number: '934', order: 934, title: "Voluntad de novar", text: "Voluntad de novar. La voluntad de novar es requisito esencial de la novación. En caso de duda, se presume que la nueva obligación contraída para cumplir la anterior no causa su extinción.", plainLanguageExplanation: "Establece el régimen de voluntad de novar. La voluntad de novar es requisito esencial de la novación.", practicalEffects: ['En la práctica, este artículo rige voluntad de novar. La voluntad de novar es requisito esencial de la novación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['voluntad', 'novar', 'articulo 934'], segments: [], amendments: [] },
  { id: 'ccyc-art-935', lawId: 'codigo-civil-comercial', number: '935', order: 935, title: "Modificaciones que no importan novación", text: "Modificaciones que no importan novación. La entrega de documentos suscriptos por el deudor en pago de la deuda y, en general, cualquier modificación accesoria de la obligación primitiva, no comporta novación.", plainLanguageExplanation: "Establece el régimen de modificaciones que no importan novación. La entrega de documentos suscriptos por el deudor en pago de la deuda y, en general, cualquier modificación accesoria de la obligación primitiva, no comporta novación.", practicalEffects: ['En la práctica, este artículo rige modificaciones que no importan novación. La entrega de documentos suscriptos por el deudor en pago de la deuda y, en general, cualquier modificación accesoria de la obligación primitiva, no c'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modificaciones', 'importan', 'novacin', 'articulo 935'], segments: [], amendments: [] },
  { id: 'ccyc-art-936', lawId: 'codigo-civil-comercial', number: '936', order: 936, title: "Novación por cambio de deudor", text: "Novación por cambio de deudor. La novación por cambio de deudor requiere el consentimiento del acreedor.", plainLanguageExplanation: "Establece el régimen de novación por cambio de deudor. La novación por cambio de deudor requiere el consentimiento del acreedor.", practicalEffects: ['En la práctica, este artículo rige novación por cambio de deudor. La novación por cambio de deudor requiere el consentimiento del acreedor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['novacin', 'cambio', 'deudor', 'articulo 936'], segments: [], amendments: [] },
  { id: 'ccyc-art-937', lawId: 'codigo-civil-comercial', number: '937', order: 937, title: "Novación por cambio de acreedor", text: "Novación por cambio de acreedor. La novación por cambio de acreedor requiere el consentimiento del deudor. Si este consentimiento no es prestado, hay cesión de crédito.", plainLanguageExplanation: "Establece el régimen de novación por cambio de acreedor. La novación por cambio de acreedor requiere el consentimiento del deudor.", practicalEffects: ['En la práctica, este artículo rige novación por cambio de acreedor. La novación por cambio de acreedor requiere el consentimiento del deudor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['novacin', 'cambio', 'acreedor', 'articulo 937'], segments: [], amendments: [] },
  { id: 'ccyc-art-938', lawId: 'codigo-civil-comercial', number: '938', order: 938, title: "Circunstancias de la obligación anterior", text: "Circunstancias de la obligación anterior. No hay novación, si la obligación anterior: a) está extinguida, o afectada de nulidad absoluta; cuando se trata de nulidad relativa, la novación vale, si al mismo tiempo se la confirma; b) estaba sujeta a condición suspensiva y, después de la novación, el hecho condicionante fracasa; o a condición resolutoria retroactiva, y el hecho condicionante se cumple; en estos casos, la nueva obligación produce los efectos que, como tal, le corresponden, pero no sustituye a la anterior.", plainLanguageExplanation: "Establece el régimen de circunstancias de la obligación anterior. No hay novación, si la obligación anterior: a) está extinguida, o afectada de nulidad absoluta; cuando se trata de nulidad relativa, la novación vale, si al mismo tiempo se la confirma; b) estaba sujeta a condición suspensiva y, después de la novación, el hecho condicionante frac", practicalEffects: ['En la práctica, este artículo rige circunstancias de la obligación anterior. No hay novación, si la obligación anterior: a) está extinguida, o afectada de nulidad absoluta; cuando se trata de nulidad relativa, la novación vale,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['circunstancias', 'obligacin', 'anterior', 'articulo 938'], segments: [], amendments: [] },
  { id: 'ccyc-art-939', lawId: 'codigo-civil-comercial', number: '939', order: 939, title: "Circunstancias de la nueva obligación", text: "Circunstancias de la nueva obligación. No hay novación y subsiste la obligación anterior, si la nueva: a) está afectada de nulidad absoluta, o de nulidad relativa y no se la confirma ulteriormente; b) está sujeta a condición suspensiva, y el hecho condicionante fracasa; o a condición resolutoria retroactiva y el hecho condicionante se cumple.", plainLanguageExplanation: "Establece el régimen de circunstancias de la nueva obligación. No hay novación y subsiste la obligación anterior, si la nueva: a) está afectada de nulidad absoluta, o de nulidad relativa y no se la confirma ulteriormente; b) está sujeta a condición suspensiva, y el hecho condicionante fracasa; o a condición resolutoria retroactiva y el hecho", practicalEffects: ['En la práctica, este artículo rige circunstancias de la nueva obligación. No hay novación y subsiste la obligación anterior, si la nueva: a) está afectada de nulidad absoluta, o de nulidad relativa y no se la confirma ulteri'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['circunstancias', 'nueva', 'obligacin', 'articulo 939'], segments: [], amendments: [] },
  { id: 'ccyc-art-940', lawId: 'codigo-civil-comercial', number: '940', order: 940, title: "Efectos", text: "Efectos. La novación extingue la obligación originaria con sus accesorios. El acreedor puede impedir la extinción de las garantías personales o reales del antiguo crédito mediante reserva; en tal caso, las garantías pasan a la nueva obligación sólo si quien las constituyó participó en el acuerdo novatorio.", plainLanguageExplanation: "Establece el régimen de efectos. La novación extingue la obligación originaria con sus accesorios.", practicalEffects: ['En la práctica, este artículo rige efectos. La novación extingue la obligación originaria con sus accesorios.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 940'], segments: [], amendments: [] },
  { id: 'ccyc-art-941', lawId: 'codigo-civil-comercial', number: '941', order: 941, title: "Novación legal", text: "Novación legal. Las disposiciones de esta Sección se aplican supletoriamente cuando la novación se produce por disposición de la ley. SECCION 4ª Dación en pago", plainLanguageExplanation: "Establece el régimen de novación legal. Las disposiciones de esta Sección se aplican supletoriamente cuando la novación se produce por disposición de la ley.", practicalEffects: ['En la práctica, este artículo rige novación legal. Las disposiciones de esta Sección se aplican supletoriamente cuando la novación se produce por disposición de la ley.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['novacin', 'legal', 'articulo 941'], segments: [], amendments: [] },
  { id: 'ccyc-art-942', lawId: 'codigo-civil-comercial', number: '942', order: 942, title: "Definición", text: "Definición. La obligación se extingue cuando el acreedor voluntariamente acepta en pago una prestación diversa de la adeudada.", plainLanguageExplanation: "Establece el régimen de definición. La obligación se extingue cuando el acreedor voluntariamente acepta en pago una prestación diversa de la adeudada.", practicalEffects: ['En la práctica, este artículo rige definición. La obligación se extingue cuando el acreedor voluntariamente acepta en pago una prestación diversa de la adeudada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 942'], segments: [], amendments: [] },
  { id: 'ccyc-art-943', lawId: 'codigo-civil-comercial', number: '943', order: 943, title: "Reglas aplicables", text: "Reglas aplicables. La dación en pago se rige por las disposiciones aplicables al contrato con el que tenga mayor afinidad. El deudor responde por la evicción y los vicios redhibitorios de lo entregado; estos efectos no hacen renacer la obligación primitiva, excepto pacto expreso y sin perjuicio de terceros. SECCION 5ª Renuncia y remisión", plainLanguageExplanation: "Establece el régimen de reglas aplicables. La dación en pago se rige por las disposiciones aplicables al contrato con el que tenga mayor afinidad.", practicalEffects: ['En la práctica, este artículo rige reglas aplicables. La dación en pago se rige por las disposiciones aplicables al contrato con el que tenga mayor afinidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglas', 'aplicables', 'articulo 943'], segments: [], amendments: [] },
  { id: 'ccyc-art-944', lawId: 'codigo-civil-comercial', number: '944', order: 944, title: "Caracteres", text: "Caracteres. Toda persona puede renunciar a los derechos conferidos por la ley cuando la renuncia no está prohibida y sólo afecta intereses privados. No se admite la renuncia anticipada de las defensas que puedan hacerse valer en juicio.", plainLanguageExplanation: "Establece el régimen de caracteres. Toda persona puede renunciar a los derechos conferidos por la ley cuando la renuncia no está prohibida y sólo afecta intereses privados.", practicalEffects: ['En la práctica, este artículo rige caracteres. Toda persona puede renunciar a los derechos conferidos por la ley cuando la renuncia no está prohibida y sólo afecta intereses privados.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caracteresarticulo 944'], segments: [], amendments: [] },
  { id: 'ccyc-art-945', lawId: 'codigo-civil-comercial', number: '945', order: 945, title: "Renuncia onerosa y gratuita", text: "Renuncia onerosa y gratuita. Si la renuncia se hace por un precio, o a cambio de una ventaja cualquiera, es regida por los principios de los contratos onerosos. La renuncia gratuita de un derecho sólo puede ser hecha por quien tiene capacidad para donar.", plainLanguageExplanation: "Establece el régimen de renuncia onerosa y gratuita. Si la renuncia se hace por un precio, o a cambio de una ventaja cualquiera, es regida por los principios de los contratos onerosos.", practicalEffects: ['En la práctica, este artículo rige renuncia onerosa y gratuita. Si la renuncia se hace por un precio, o a cambio de una ventaja cualquiera, es regida por los principios de los contratos onerosos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['renuncia', 'onerosa', 'gratuita', 'articulo 945'], segments: [], amendments: [] },
  { id: 'ccyc-art-946', lawId: 'codigo-civil-comercial', number: '946', order: 946, title: "Aceptación", text: "Aceptación. La aceptación de la renuncia por el beneficiario causa la extinción del derecho.", plainLanguageExplanation: "Establece el régimen de aceptación. La aceptación de la renuncia por el beneficiario causa la extinción del derecho.", practicalEffects: ['En la práctica, este artículo rige aceptación. La aceptación de la renuncia por el beneficiario causa la extinción del derecho.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aceptacinarticulo 946'], segments: [], amendments: [] },
  { id: 'ccyc-art-947', lawId: 'codigo-civil-comercial', number: '947', order: 947, title: "Retractación", text: "Retractación. La renuncia puede ser retractada mientras no haya sido aceptada, quedando a salvo los derechos adquiridos por terceros.", plainLanguageExplanation: "Establece el régimen de retractación. La renuncia puede ser retractada mientras no haya sido aceptada, quedando a salvo los derechos adquiridos por terceros.", practicalEffects: ['En la práctica, este artículo rige retractación. La renuncia puede ser retractada mientras no haya sido aceptada, quedando a salvo los derechos adquiridos por terceros.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['retractacinarticulo 947'], segments: [], amendments: [] },
  { id: 'ccyc-art-948', lawId: 'codigo-civil-comercial', number: '948', order: 948, title: "Prueba", text: "Prueba. La voluntad de renunciar no se presume y la interpretación de los actos que permiten inducirla es restrictiva.", plainLanguageExplanation: "Establece el régimen de prueba. La voluntad de renunciar no se presume y la interpretación de los actos que permiten inducirla es restrictiva.", practicalEffects: ['En la práctica, este artículo rige prueba. La voluntad de renunciar no se presume y la interpretación de los actos que permiten inducirla es restrictiva.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pruebaarticulo 948'], segments: [], amendments: [] },
  { id: 'ccyc-art-949', lawId: 'codigo-civil-comercial', number: '949', order: 949, title: "Forma", text: "Forma. La renuncia no está sujeta a formas especiales, aun cuando se refiera a derechos que constan en un instrumento público.", plainLanguageExplanation: "Establece el régimen de forma. La renuncia no está sujeta a formas especiales, aun cuando se refiera a derechos que constan en un instrumento público.", practicalEffects: ['En la práctica, este artículo rige forma. La renuncia no está sujeta a formas especiales, aun cuando se refiera a derechos que constan en un instrumento público.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formaarticulo 949'], segments: [], amendments: [] },
  { id: 'ccyc-art-950', lawId: 'codigo-civil-comercial', number: '950', order: 950, title: "Remisión", text: "Remisión. Se considera remitida la deuda, excepto prueba en contrario, cuando el acreedor entrega voluntariamente al deudor el documento original en que consta la deuda. Si el documento es un instrumento protocolizado y su testimonio o copia se halla en poder del deudor sin anotación del pago o remisión, y tampoco consta el pago o la remisión en el documento original, el deudor debe probar que el acreedor le entregó el testimonio de la copia como remisión de la deuda.", plainLanguageExplanation: "Establece el régimen de remisión. Se considera remitida la deuda, excepto prueba en contrario, cuando el acreedor entrega voluntariamente al deudor el documento original en que consta la deuda.", practicalEffects: ['En la práctica, este artículo rige remisión. Se considera remitida la deuda, excepto prueba en contrario, cuando el acreedor entrega voluntariamente al deudor el documento original en que consta la deuda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remisinarticulo 950'], segments: [], amendments: [] },
  { id: 'ccyc-art-951', lawId: 'codigo-civil-comercial', number: '951', order: 951, title: "Normas aplicables", text: "Normas aplicables. Las disposiciones sobre la renuncia se aplican a la remisión de la deuda hecha por el acreedor.", plainLanguageExplanation: "Establece el régimen de normas aplicables. Las disposiciones sobre la renuncia se aplican a la remisión de la deuda hecha por el acreedor.", practicalEffects: ['En la práctica, este artículo rige normas aplicables. Las disposiciones sobre la renuncia se aplican a la remisión de la deuda hecha por el acreedor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['normas', 'aplicables', 'articulo 951'], segments: [], amendments: [] },
  { id: 'ccyc-art-952', lawId: 'codigo-civil-comercial', number: '952', order: 952, title: "Efectos", text: "Efectos. La remisión de la deuda produce los efectos del pago. Sin embargo, la remisión en favor del fiador no aprovecha al deudor. La hecha a favor de uno de varios fiadores no aprovecha a los demás.", plainLanguageExplanation: "Establece el régimen de efectos. La remisión de la deuda produce los efectos del pago.", practicalEffects: ['En la práctica, este artículo rige efectos. La remisión de la deuda produce los efectos del pago.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 952'], segments: [], amendments: [] },
  { id: 'ccyc-art-953', lawId: 'codigo-civil-comercial', number: '953', order: 953, title: "Pago parcial del fiador", text: "Pago parcial del fiador. El fiador que pagó una parte de la deuda antes de la remisión hecha al deudor, no puede repetir el pago contra el acreedor.", plainLanguageExplanation: "Establece el régimen de pago parcial del fiador. El fiador que pagó una parte de la deuda antes de la remisión hecha al deudor, no puede repetir el pago contra el acreedor.", practicalEffects: ['En la práctica, este artículo rige pago parcial del fiador. El fiador que pagó una parte de la deuda antes de la remisión hecha al deudor, no puede repetir el pago contra el acreedor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pago', 'parcial', 'fiador', 'articulo 953'], segments: [], amendments: [] },
  { id: 'ccyc-art-954', lawId: 'codigo-civil-comercial', number: '954', order: 954, title: "Entrega de la cosa dada en prenda", text: "Entrega de la cosa dada en prenda. La restitución al deudor de la cosa dada en prenda causa sólo la remisión de la prenda, pero no la remisión de la deuda. SECCION 6ª Imposibilidad de cumplimiento", plainLanguageExplanation: "Establece el régimen de entrega de la cosa dada en prenda. La restitución al deudor de la cosa dada en prenda causa sólo la remisión de la prenda, pero no la remisión de la deuda.", practicalEffects: ['En la práctica, este artículo rige entrega de la cosa dada en prenda. La restitución al deudor de la cosa dada en prenda causa sólo la remisión de la prenda, pero no la remisión de la deuda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['entrega', 'cosa', 'dada', 'prenda', 'articulo 954'], segments: [], amendments: [] },
  { id: 'ccyc-art-955', lawId: 'codigo-civil-comercial', number: '955', order: 955, title: "Definición", text: "Definición. La imposibilidad sobrevenida, objetiva, absoluta y definitiva de la prestación, producida por caso fortuito o fuerza mayor, extingue la obligación, sin responsabilidad. Si la imposibilidad sobreviene debido a causas imputables al deudor, la obligación modifica su objeto y se convierte en la de pagar una indemnización de los daños causados.", plainLanguageExplanation: "Establece el régimen de definición. La imposibilidad sobrevenida, objetiva, absoluta y definitiva de la prestación, producida por caso fortuito o fuerza mayor, extingue la obligación, sin responsabilidad.", practicalEffects: ['En la práctica, este artículo rige definición. La imposibilidad sobrevenida, objetiva, absoluta y definitiva de la prestación, producida por caso fortuito o fuerza mayor, extingue la obligación, sin responsabilidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 955'], segments: [], amendments: [] },
  { id: 'ccyc-art-956', lawId: 'codigo-civil-comercial', number: '956', order: 956, title: "Imposibilidad temporaria", text: "Imposibilidad temporaria. La imposibilidad sobrevenida, objetiva, absoluta y temporaria de la prestación tiene efecto extintivo cuando el plazo es esencial, o cuando su duración frustra el interés del acreedor de modo irreversible. TITULO II Contratos en general CAPITULO 1 Disposiciones generales", plainLanguageExplanation: "Establece el régimen de imposibilidad temporaria. La imposibilidad sobrevenida, objetiva, absoluta y temporaria de la prestación tiene efecto extintivo cuando el plazo es esencial, o cuando su duración frustra el interés del acreedor de modo irreversible.", practicalEffects: ['En la práctica, este artículo rige imposibilidad temporaria. La imposibilidad sobrevenida, objetiva, absoluta y temporaria de la prestación tiene efecto extintivo cuando el plazo es esencial, o cuando su duració'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['imposibilidad', 'temporaria', 'articulo 956'], segments: [], amendments: [] },
  { id: 'ccyc-art-957', lawId: 'codigo-civil-comercial', number: '957', order: 957, title: "Definición", text: "Definición. Contrato es el acto jurídico mediante el cual dos o más partes manifiestan su consentimiento para crear, regular, modificar, transferir o extinguir relaciones jurídicas patrimoniales.", plainLanguageExplanation: "Establece el régimen de definición. Contrato es el acto jurídico mediante el cual dos o más partes manifiestan su consentimiento para crear, regular, modificar, transferir o extinguir relaciones jurídicas patrimoniales.", practicalEffects: ['En la práctica, este artículo rige definición. Contrato es el acto jurídico mediante el cual dos o más partes manifiestan su consentimiento para crear, regular, modificar, transferir o extinguir re'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 957'], segments: [], amendments: [] },
  { id: 'ccyc-art-958', lawId: 'codigo-civil-comercial', number: '958', order: 958, title: "Libertad de contratación", text: "Libertad de contratación. Las partes son libres para celebrar un contrato y determinar su contenido, dentro de los límites impuestos por la ley o el orden público. Las normas legales siempre son de aplicación supletoria a la voluntad de las partes expresada en el contrato, aunque la ley no lo determine en forma expresa para un tipo contractual determinado, salvo que la norma sea expresamente imperativa, y siempre con interpretación restrictiva. (Artículo sustituido por art. 252 del Decreto N° 70/2023 B.O. 21/12/2023)", plainLanguageExplanation: "Establece el régimen de libertad de contratación. Las partes son libres para celebrar un contrato y determinar su contenido, dentro de los límites impuestos por la ley o el orden público.", practicalEffects: ['En la práctica, este artículo rige libertad de contratación. Las partes son libres para celebrar un contrato y determinar su contenido, dentro de los límites impuestos por la ley o el orden público.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad', 'contratacin', 'articulo 958'], segments: [], amendments: [] },
  { id: 'ccyc-art-959', lawId: 'codigo-civil-comercial', number: '959', order: 959, title: "Efecto vinculante", text: "Efecto vinculante. Todo contrato válidamente celebrado es obligatorio para las partes. Su contenido sólo puede ser modificado o extinguido por acuerdo de partes o en los supuestos en que la ley lo prevé.", plainLanguageExplanation: "Establece el régimen de efecto vinculante. Todo contrato válidamente celebrado es obligatorio para las partes.", practicalEffects: ['En la práctica, este artículo rige efecto vinculante. Todo contrato válidamente celebrado es obligatorio para las partes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efecto', 'vinculante', 'articulo 959'], segments: [], amendments: [] },
  { id: 'ccyc-art-960', lawId: 'codigo-civil-comercial', number: '960', order: 960, title: "Facultades de los jueces", text: "Facultades de los jueces. Los jueces no tienen facultades para modificar las estipulaciones de los contratos, excepto que sea a pedido de una de las partes cuando lo autoriza la ley. (Artículo sustituido por art. 253 del Decreto N° 70/2023 B.O. 21/12/2023)", plainLanguageExplanation: "Establece el régimen de facultades de los jueces. Los jueces no tienen facultades para modificar las estipulaciones de los contratos, excepto que sea a pedido de una de las partes cuando lo autoriza la ley.", practicalEffects: ['En la práctica, este artículo rige facultades de los jueces. Los jueces no tienen facultades para modificar las estipulaciones de los contratos, excepto que sea a pedido de una de las partes cuando lo autoriza la ley.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['facultades', 'jueces', 'articulo 960'], segments: [], amendments: [] },
  { id: 'ccyc-art-961', lawId: 'codigo-civil-comercial', number: '961', order: 961, title: "Buena fe", text: "Buena fe. Los contratos deben celebrarse, interpretarse y ejecutarse de buena fe. Obligan no sólo a lo que está formalmente expresado, sino a todas las consecuencias que puedan considerarse comprendidas en ellos, con los alcances en que razonablemente se habría obligado un contratante cuidadoso y previsor.", plainLanguageExplanation: "Establece el régimen de buena fe. Los contratos deben celebrarse, interpretarse y ejecutarse de buena fe.", practicalEffects: ['En la práctica, este artículo rige buena fe. Los contratos deben celebrarse, interpretarse y ejecutarse de buena fe.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['buenaarticulo 961'], segments: [], amendments: [] },
  { id: 'ccyc-art-962', lawId: 'codigo-civil-comercial', number: '962', order: 962, title: "Carácter de las normas legales", text: "Carácter de las normas legales. Las normas legales relativas a los contratos son supletorias de la voluntad de las partes, a menos que de su modo de expresión, de su contenido, o de su contexto, resulte su carácter indisponible.", plainLanguageExplanation: "Establece el régimen de carácter de las normas legales. Las normas legales relativas a los contratos son supletorias de la voluntad de las partes, a menos que de su modo de expresión, de su contenido, o de su contexto, resulte su carácter indisponible.", practicalEffects: ['En la práctica, este artículo rige carácter de las normas legales. Las normas legales relativas a los contratos son supletorias de la voluntad de las partes, a menos que de su modo de expresión, de su contenido, o de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['carcter', 'normas', 'legales', 'articulo 962'], segments: [], amendments: [] },
  { id: 'ccyc-art-963', lawId: 'codigo-civil-comercial', number: '963', order: 963, title: "Prelación normativa", text: "Prelación normativa. Cuando concurren disposiciones de este Código y de alguna ley especial, las normas se aplican con el siguiente orden de prelación: a) normas indisponibles de la ley especial y de este Código; b) normas particulares del contrato; c) normas supletorias de la ley especial; d) normas supletorias de este Código.", plainLanguageExplanation: "Establece el régimen de prelación normativa. Cuando concurren disposiciones de este Código y de alguna ley especial, las normas se aplican con el siguiente orden de prelación: a) normas indisponibles de la ley especial y de este Código; b) normas particulares del contrato; c) normas supletorias de la ley especial; d) normas", practicalEffects: ['En la práctica, este artículo rige prelación normativa. Cuando concurren disposiciones de este Código y de alguna ley especial, las normas se aplican con el siguiente orden de prelación: a) normas indisponi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prelacin', 'normativa', 'articulo 963'], segments: [], amendments: [] },
  { id: 'ccyc-art-964', lawId: 'codigo-civil-comercial', number: '964', order: 964, title: "Integración del contrato", text: "Integración del contrato. El contenido del contrato se integra con: a) las normas indisponibles, que se aplican en sustitución de las cláusulas incompatibles con ellas; b) las normas supletorias; c) los usos y prácticas del lugar de celebración, en cuanto sean aplicables porque hayan sido declarados obligatorios por las partes o porque sean ampliamente conocidos y regularmente observados en el ámbito en que se celebra el contrato, excepto que su aplicación sea irrazonable.", plainLanguageExplanation: "Establece el régimen de integración del contrato. El contenido del contrato se integra con: a) las normas indisponibles, que se aplican en sustitución de las cláusulas incompatibles con ellas; b) las normas supletorias; c) los usos y prácticas del lugar de celebración, en cuanto sean aplicables porque hayan sido declarados oblig", practicalEffects: ['En la práctica, este artículo rige integración del contrato. El contenido del contrato se integra con: a) las normas indisponibles, que se aplican en sustitución de las cláusulas incompatibles con ellas; b) las'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['integracin', 'contrato', 'articulo 964'], segments: [], amendments: [] },
  { id: 'ccyc-art-965', lawId: 'codigo-civil-comercial', number: '965', order: 965, title: "Derecho de propiedad", text: "Derecho de propiedad. Los derechos resultantes de los contratos integran el derecho de propiedad del contratante. CAPITULO 2 Clasificación de los contratos", plainLanguageExplanation: "Establece el régimen de derecho de propiedad. Los derechos resultantes de los contratos integran el derecho de propiedad del contratante.", practicalEffects: ['En la práctica, este artículo rige derecho de propiedad. Los derechos resultantes de los contratos integran el derecho de propiedad del contratante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'propiedad', 'articulo 965'], segments: [], amendments: [] },
  { id: 'ccyc-art-966', lawId: 'codigo-civil-comercial', number: '966', order: 966, title: "Contratos unilaterales y bilaterales", text: "Contratos unilaterales y bilaterales. Los contratos son unilaterales cuando una de las partes se obliga hacia la otra sin que ésta quede obligada. Son bilaterales cuando las partes se obligan recíprocamente la una hacia la otra. Las normas de los contratos bilaterales se aplican supletoriamente a los contratos plurilaterales.", plainLanguageExplanation: "Establece el régimen de contratos unilaterales y bilaterales. Los contratos son unilaterales cuando una de las partes se obliga hacia la otra sin que ésta quede obligada.", practicalEffects: ['En la práctica, este artículo rige contratos unilaterales y bilaterales. Los contratos son unilaterales cuando una de las partes se obliga hacia la otra sin que ésta quede obligada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'unilaterales', 'bilaterales', 'articulo 966'], segments: [], amendments: [] },
  { id: 'ccyc-art-967', lawId: 'codigo-civil-comercial', number: '967', order: 967, title: "Contratos a título oneroso y a título gratuito", text: "Contratos a título oneroso y a título gratuito. Los contratos son a título oneroso cuando las ventajas que procuran a una de las partes les son concedidas por una prestación que ella ha hecho o se obliga a hacer a la otra. Son a título gratuito cuando aseguran a uno o a otro de los contratantes alguna ventaja, independiente de toda prestación a su cargo.", plainLanguageExplanation: "Establece el régimen de contratos a título oneroso y a título gratuito. Los contratos son a título oneroso cuando las ventajas que procuran a una de las partes les son concedidas por una prestación que ella ha hecho o se obliga a hacer a la otra.", practicalEffects: ['En la práctica, este artículo rige contratos a título oneroso y a título gratuito. Los contratos son a título oneroso cuando las ventajas que procuran a una de las partes les son concedidas por una prestación que ella ha hecho o se obliga a hacer a la otra.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'ttulo', 'oneroso', 'gratuito', 'articulo 967'], segments: [], amendments: [] },
  { id: 'ccyc-art-968', lawId: 'codigo-civil-comercial', number: '968', order: 968, title: "Contratos conmutativos y aleatorios", text: "Contratos conmutativos y aleatorios. Los contratos a título oneroso son conmutativos cuando las ventajas para todos los contratantes son ciertas. Son aleatorios, cuando las ventajas o las pérdidas, para uno de ellos o para todos, dependen de un acontecimiento incierto.", plainLanguageExplanation: "Establece el régimen de contratos conmutativos y aleatorios. Los contratos a título oneroso son conmutativos cuando las ventajas para todos los contratantes son ciertas.", practicalEffects: ['En la práctica, este artículo rige contratos conmutativos y aleatorios. Los contratos a título oneroso son conmutativos cuando las ventajas para todos los contratantes son ciertas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'conmutativos', 'aleatorios', 'articulo 968'], segments: [], amendments: [] },
  { id: 'ccyc-art-969', lawId: 'codigo-civil-comercial', number: '969', order: 969, title: "Contratos formales", text: "Contratos formales. Los contratos para los cuales la ley exige una forma para su validez, son nulos si la solemnidad no ha sido satisfecha. Cuando la forma requerida para los contratos, lo es sólo para que éstos produzcan sus efectos propios, sin sanción de nulidad, no quedan concluidos como tales mientras no se ha otorgado el instrumento previsto, pero valen como contratos en los que las partes se obligaron a cumplir con la expresada formalidad. Cuando la ley o las partes no imponen una forma determinada, ésta debe constituir sólo un medio de prueba de la celebración del contrato.", plainLanguageExplanation: "Establece el régimen de contratos formales. Los contratos para los cuales la ley exige una forma para su validez, son nulos si la solemnidad no ha sido satisfecha.", practicalEffects: ['En la práctica, este artículo rige contratos formales. Los contratos para los cuales la ley exige una forma para su validez, son nulos si la solemnidad no ha sido satisfecha.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'formales', 'articulo 969'], segments: [], amendments: [] },
  { id: 'ccyc-art-970', lawId: 'codigo-civil-comercial', number: '970', order: 970, title: "Contratos nominados e innominados", text: "Contratos nominados e innominados. Los contratos son nominados e innominados según que la ley los regule especialmente o no. Los contratos innominados están regidos, en el siguiente orden, por: a) la voluntad de las partes; b) las normas generales sobre contratos y obligaciones; c) los usos y prácticas del lugar de celebración; d) las disposiciones correspondientes a los contratos nominados afines que son compatibles y se adecuan a su finalidad. CAPITULO 3 Formación del consentimiento SECCION 1ª Consentimiento, oferta y aceptación", plainLanguageExplanation: "Establece el régimen de contratos nominados e innominados. Los contratos son nominados e innominados según que la ley los regule especialmente o no.", practicalEffects: ['En la práctica, este artículo rige contratos nominados e innominados. Los contratos son nominados e innominados según que la ley los regule especialmente o no.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'nominados', 'innominados', 'articulo 970'], segments: [], amendments: [] },
  { id: 'ccyc-art-971', lawId: 'codigo-civil-comercial', number: '971', order: 971, title: "Formación del consentimiento", text: "Formación del consentimiento. Los contratos se concluyen con la recepción de la aceptación de una oferta o por una conducta de las partes que sea suficiente para demostrar la existencia de un acuerdo.", plainLanguageExplanation: "Establece el régimen de formación del consentimiento. Los contratos se concluyen con la recepción de la aceptación de una oferta o por una conducta de las partes que sea suficiente para demostrar la existencia de un acuerdo.", practicalEffects: ['En la práctica, este artículo rige formación del consentimiento. Los contratos se concluyen con la recepción de la aceptación de una oferta o por una conducta de las partes que sea suficiente para demostrar la exist'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formacin', 'consentimiento', 'articulo 971'], segments: [], amendments: [] },
  { id: 'ccyc-art-972', lawId: 'codigo-civil-comercial', number: '972', order: 972, title: "Oferta", text: "Oferta. La oferta es la manifestación dirigida a persona determinada o determinable, con la intención de obligarse y con las precisiones necesarias para establecer los efectos que debe producir de ser aceptada.", plainLanguageExplanation: "Establece el régimen de oferta. La oferta es la manifestación dirigida a persona determinada o determinable, con la intención de obligarse y con las precisiones necesarias para establecer los efectos que debe producir de ser aceptada.", practicalEffects: ['En la práctica, este artículo rige oferta. La oferta es la manifestación dirigida a persona determinada o determinable, con la intención de obligarse y con las precisiones necesarias para estab'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ofertaarticulo 972'], segments: [], amendments: [] },
  { id: 'ccyc-art-973', lawId: 'codigo-civil-comercial', number: '973', order: 973, title: "Invitación a ofertar", text: "Invitación a ofertar. La oferta dirigida a personas indeterminadas es considerada como invitación para que hagan ofertas, excepto que de sus términos o de las circunstancias de su emisión resulte la intención de contratar del oferente. En este caso, se la entiende emitida por el tiempo y en las condiciones admitidas por los usos.", plainLanguageExplanation: "Establece el régimen de invitación a ofertar. La oferta dirigida a personas indeterminadas es considerada como invitación para que hagan ofertas, excepto que de sus términos o de las circunstancias de su emisión resulte la intención de contratar del oferente.", practicalEffects: ['En la práctica, este artículo rige invitación a ofertar. La oferta dirigida a personas indeterminadas es considerada como invitación para que hagan ofertas, excepto que de sus términos o de las circunstancia'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['invitacin', 'ofertar', 'articulo 973'], segments: [], amendments: [] },
  { id: 'ccyc-art-974', lawId: 'codigo-civil-comercial', number: '974', order: 974, title: "Fuerza obligatoria de la oferta", text: "Fuerza obligatoria de la oferta. La oferta obliga al proponente, a no ser que lo contrario resulte de sus términos, de la naturaleza del negocio o de las circunstancias del caso. La oferta hecha a una persona presente o la formulada por un medio de comunicación instantáneo, sin fijación de plazo, sólo puede ser aceptada inmediatamente. Cuando se hace a una persona que no está presente, sin fijación de plazo para la aceptación, el proponente queda obligado hasta el momento en que puede razonablemente esperarse la recepción de la respuesta, expedida por los medios usuales de comunicación. Los plazos de vigencia de la oferta comienzan a correr desde la fecha de su recepción, excepto que contenga una previsión diferente.", plainLanguageExplanation: "Establece el régimen de fuerza obligatoria de la oferta. La oferta obliga al proponente, a no ser que lo contrario resulte de sus términos, de la naturaleza del negocio o de las circunstancias del caso.", practicalEffects: ['En la práctica, este artículo rige fuerza obligatoria de la oferta. La oferta obliga al proponente, a no ser que lo contrario resulte de sus términos, de la naturaleza del negocio o de las circunstancias del caso.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fuerza', 'obligatoria', 'oferta', 'articulo 974'], segments: [], amendments: [] },
  { id: 'ccyc-art-975', lawId: 'codigo-civil-comercial', number: '975', order: 975, title: "Retractación de la oferta", text: "Retractación de la oferta. La oferta dirigida a una persona determinada puede ser retractada si la comunicación de su retiro es recibida por el destinatario antes o al mismo tiempo que la oferta.", plainLanguageExplanation: "Establece el régimen de retractación de la oferta. La oferta dirigida a una persona determinada puede ser retractada si la comunicación de su retiro es recibida por el destinatario antes o al mismo tiempo que la oferta.", practicalEffects: ['En la práctica, este artículo rige retractación de la oferta. La oferta dirigida a una persona determinada puede ser retractada si la comunicación de su retiro es recibida por el destinatario antes o al mismo tie'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['retractacin', 'oferta', 'articulo 975'], segments: [], amendments: [] },
  { id: 'ccyc-art-976', lawId: 'codigo-civil-comercial', number: '976', order: 976, title: "Muerte o incapacidad de las partes", text: "Muerte o incapacidad de las partes. La oferta caduca cuando el proponente o el destinatario de ella fallecen o se incapacitan, antes de la recepción de su aceptación. El que aceptó la oferta ignorando la muerte o incapacidad del oferente, y que a consecuencia de su aceptación ha hecho gastos o sufrido pérdidas, tiene derecho a reclamar su reparación.", plainLanguageExplanation: "Establece el régimen de muerte o incapacidad de las partes. La oferta caduca cuando el proponente o el destinatario de ella fallecen o se incapacitan, antes de la recepción de su aceptación.", practicalEffects: ['En la práctica, este artículo rige muerte o incapacidad de las partes. La oferta caduca cuando el proponente o el destinatario de ella fallecen o se incapacitan, antes de la recepción de su aceptación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['muerte', 'incapacidad', 'partes', 'articulo 976'], segments: [], amendments: [] },
  { id: 'ccyc-art-977', lawId: 'codigo-civil-comercial', number: '977', order: 977, title: "Contrato plurilateral", text: "Contrato plurilateral. Si el contrato ha de ser celebrado por varias partes, y la oferta emana de distintas personas, o es dirigida a varios destinatarios, no hay contrato sin el consentimiento de todos los interesados, excepto que la convención o la ley autoricen a la mayoría de ellos para celebrarlo en nombre de todos o permitan su conclusión sólo entre quienes lo han consentido.", plainLanguageExplanation: "Establece el régimen de contrato plurilateral. Si el contrato ha de ser celebrado por varias partes, y la oferta emana de distintas personas, o es dirigida a varios destinatarios, no hay contrato sin el consentimiento de todos los interesados, excepto que la convención o la ley autoricen a la mayoría de ellos para celebrarlo", practicalEffects: ['En la práctica, este artículo rige contrato plurilateral. Si el contrato ha de ser celebrado por varias partes, y la oferta emana de distintas personas, o es dirigida a varios destinatarios, no hay contrato s'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contrato', 'plurilateral', 'articulo 977'], segments: [], amendments: [] },
  { id: 'ccyc-art-978', lawId: 'codigo-civil-comercial', number: '978', order: 978, title: "Aceptación", text: "Aceptación. Para que el contrato se concluya, la aceptación debe expresar la plena conformidad con la oferta. Cualquier modificación a la oferta que su destinatario hace al manifestar su aceptación, no vale como tal, sino que importa la propuesta de un nuevo contrato, pero las modificaciones pueden ser admitidas por el oferente si lo comunica de inmediato al aceptante.", plainLanguageExplanation: "Establece el régimen de aceptación. Para que el contrato se concluya, la aceptación debe expresar la plena conformidad con la oferta.", practicalEffects: ['En la práctica, este artículo rige aceptación. Para que el contrato se concluya, la aceptación debe expresar la plena conformidad con la oferta.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aceptacinarticulo 978'], segments: [], amendments: [] },
  { id: 'ccyc-art-979', lawId: 'codigo-civil-comercial', number: '979', order: 979, title: "Modos de aceptación", text: "Modos de aceptación. Toda declaración o acto del destinatario que revela conformidad con la oferta constituye aceptación. El silencio importa aceptación sólo cuando existe el deber de expedirse, el que puede resultar de la voluntad de las partes, de los usos o de las prácticas que las partes hayan establecido entre ellas, o de una relación entre el silencio actual y las declaraciones precedentes.", plainLanguageExplanation: "Establece el régimen de modos de aceptación. Toda declaración o acto del destinatario que revela conformidad con la oferta constituye aceptación.", practicalEffects: ['En la práctica, este artículo rige modos de aceptación. Toda declaración o acto del destinatario que revela conformidad con la oferta constituye aceptación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modos', 'aceptacin', 'articulo 979'], segments: [], amendments: [] },
  { id: 'ccyc-art-980', lawId: 'codigo-civil-comercial', number: '980', order: 980, title: "Perfeccionamiento", text: "Perfeccionamiento. La aceptación perfecciona el contrato: a) entre presentes, cuando es manifestada; b) entre ausentes, si es recibida por el proponente durante el plazo de vigencia de la oferta.", plainLanguageExplanation: "Establece el régimen de perfeccionamiento. La aceptación perfecciona el contrato: a) entre presentes, cuando es manifestada; b) entre ausentes, si es recibida por el proponente durante el plazo de vigencia de la oferta.", practicalEffects: ['En la práctica, este artículo rige perfeccionamiento. La aceptación perfecciona el contrato: a) entre presentes, cuando es manifestada; b) entre ausentes, si es recibida por el proponente durante el plazo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['perfeccionamientoarticulo 980'], segments: [], amendments: [] },
  { id: 'ccyc-art-981', lawId: 'codigo-civil-comercial', number: '981', order: 981, title: "Retractación de la aceptación", text: "Retractación de la aceptación. La aceptación puede ser retractada si la comunicación de su retiro es recibida por el destinatario antes o al mismo tiempo que ella.", plainLanguageExplanation: "Establece el régimen de retractación de la aceptación. La aceptación puede ser retractada si la comunicación de su retiro es recibida por el destinatario antes o al mismo tiempo que ella.", practicalEffects: ['En la práctica, este artículo rige retractación de la aceptación. La aceptación puede ser retractada si la comunicación de su retiro es recibida por el destinatario antes o al mismo tiempo que ella.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['retractacin', 'aceptacin', 'articulo 981'], segments: [], amendments: [] },
  { id: 'ccyc-art-982', lawId: 'codigo-civil-comercial', number: '982', order: 982, title: "Acuerdo parcial", text: "Acuerdo parcial. Los acuerdos parciales de las partes concluyen el contrato si todas ellas, con la formalidad que en su caso corresponda, expresan su consentimiento sobre los elementos esenciales particulares. En tal situación, el contrato queda integrado conforme a las reglas del Capítulo 1. En la duda, el contrato se tiene por no concluido. No se considera acuerdo parcial la extensión de una minuta o de un borrador respecto de alguno de los elementos o de todos ellos.", plainLanguageExplanation: "Establece el régimen de acuerdo parcial. Los acuerdos parciales de las partes concluyen el contrato si todas ellas, con la formalidad que en su caso corresponda, expresan su consentimiento sobre los elementos esenciales particulares.", practicalEffects: ['En la práctica, este artículo rige acuerdo parcial. Los acuerdos parciales de las partes concluyen el contrato si todas ellas, con la formalidad que en su caso corresponda, expresan su consentimiento sobre los elementos esenciales particulares.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acuerdo', 'parcial', 'articulo 982'], segments: [], amendments: [] },
  { id: 'ccyc-art-983', lawId: 'codigo-civil-comercial', number: '983', order: 983, title: "Recepción de la manifestación de la voluntad", text: "Recepción de la manifestación de la voluntad. A los fines de este Capítulo se considera que la manifestación de voluntad de una parte es recibida por la otra cuando ésta la conoce o debió conocerla, trátese de comunicación verbal, de recepción en su domicilio de un instrumento pertinente, o de otro modo útil. SECCION 2ª Contratos celebrados por adhesión a cláusulas generales predispuestas", plainLanguageExplanation: "Establece el régimen de recepción de la manifestación de la voluntad. A los fines de este Capítulo se considera que la manifestación de voluntad de una parte es recibida por la otra cuando ésta la conoce o debió conocerla, trátese de comunicación verbal, de recepción en su domicilio de un instrumento pertinente, o de otro modo útil.", practicalEffects: ['En la práctica, este artículo rige recepción de la manifestación de la voluntad. A los fines de este Capítulo se considera que la manifestación de voluntad de una parte es recibida por la otra cuando ésta la conoce o debió conocerl'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['recepcin', 'manifestacin', 'voluntad', 'articulo 983'], segments: [], amendments: [] },
  { id: 'ccyc-art-984', lawId: 'codigo-civil-comercial', number: '984', order: 984, title: "Definición", text: "Definición. El contrato por adhesión es aquel mediante el cual uno de los contratantes adhiere a cláusulas generales predispuestas unilateralmente, por la otra parte o por un tercero, sin que el adherente haya participado en su redacción.", plainLanguageExplanation: "Establece el régimen de definición. El contrato por adhesión es aquel mediante el cual uno de los contratantes adhiere a cláusulas generales predispuestas unilateralmente, por la otra parte o por un tercero, sin que el adherente haya participado en su redacción.", practicalEffects: ['En la práctica, este artículo rige definición. El contrato por adhesión es aquel mediante el cual uno de los contratantes adhiere a cláusulas generales predispuestas unilateralmente, por la otra pa'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 984'], segments: [], amendments: [] },
  { id: 'ccyc-art-985', lawId: 'codigo-civil-comercial', number: '985', order: 985, title: "Requisitos", text: "Requisitos. Las cláusulas generales predispuestas deben ser comprensibles y autosuficientes. La redacción debe ser clara, completa y fácilmente legible. Se tienen por no convenidas aquellas que efectúan un reenvío a textos o documentos que no se facilitan a la contraparte del predisponente, previa o simultáneamente a la conclusión del contrato. La presente disposición es aplicable a la contratación telefónica, electrónica o similares.", plainLanguageExplanation: "Establece el régimen de requisitos. Las cláusulas generales predispuestas deben ser comprensibles y autosuficientes.", practicalEffects: ['En la práctica, este artículo rige requisitos. Las cláusulas generales predispuestas deben ser comprensibles y autosuficientes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 985'], segments: [], amendments: [] },
  { id: 'ccyc-art-986', lawId: 'codigo-civil-comercial', number: '986', order: 986, title: "Cláusulas particulares", text: "Cláusulas particulares. Las cláusulas particulares son aquellas que, negociadas individualmente, amplían, limitan, suprimen o interpretan una cláusula general. En caso de in-compatibilidad entre cláusulas generales y particulares, prevalecen estas últimas.", plainLanguageExplanation: "Establece el régimen de cláusulas particulares. Las cláusulas particulares son aquellas que, negociadas individualmente, amplían, limitan, suprimen o interpretan una cláusula general.", practicalEffects: ['En la práctica, este artículo rige cláusulas particulares. Las cláusulas particulares son aquellas que, negociadas individualmente, amplían, limitan, suprimen o interpretan una cláusula general.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['clusulas', 'particulares', 'articulo 986'], segments: [], amendments: [] },
  { id: 'ccyc-art-987', lawId: 'codigo-civil-comercial', number: '987', order: 987, title: "Interpretación", text: "Interpretación. Las cláusulas ambiguas predispuestas por una de las partes se interpretan en sentido contrario a la parte predisponente.", plainLanguageExplanation: "Establece el régimen de interpretación. Las cláusulas ambiguas predispuestas por una de las partes se interpretan en sentido contrario a la parte predisponente.", practicalEffects: ['En la práctica, este artículo rige interpretación. Las cláusulas ambiguas predispuestas por una de las partes se interpretan en sentido contrario a la parte predisponente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['interpretacinarticulo 987'], segments: [], amendments: [] },
  { id: 'ccyc-art-988', lawId: 'codigo-civil-comercial', number: '988', order: 988, title: "Cláusulas abusivas", text: "Cláusulas abusivas. En los contratos previstos en esta sección, se deben tener por no escritas: a) las cláusulas que desnaturalizan las obligaciones del predisponente; b) las que importan renuncia o restricción a los derechos del adherente, o amplían derechos del predisponente que resultan de normas supletorias; c) las que por su contenido, redacción o presentación, no son razonablemente previsibles.", plainLanguageExplanation: "Establece el régimen de cláusulas abusivas. En los contratos previstos en esta sección, se deben tener por no escritas: a) las cláusulas que desnaturalizan las obligaciones del predisponente; b) las que importan renuncia o restricción a los derechos del adherente, o amplían derechos del predisponente que resultan de normas", practicalEffects: ['En la práctica, este artículo rige cláusulas abusivas. En los contratos previstos en esta sección, se deben tener por no escritas: a) las cláusulas que desnaturalizan las obligaciones del predisponente; b)'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['clusulas', 'abusivas', 'articulo 988'], segments: [], amendments: [] },
  { id: 'ccyc-art-989', lawId: 'codigo-civil-comercial', number: '989', order: 989, title: "Control judicial de las cláusulas abusivas", text: "Control judicial de las cláusulas abusivas. La aprobación administrativa de las cláusulas generales no obsta a su control judicial. (Artículo sustituido por art. 254 del Decreto N° 70/2023 B.O. 21/12/2023) SECCION 3ª Tratativas contractuales", plainLanguageExplanation: "Establece el régimen de control judicial de las cláusulas abusivas. La aprobación administrativa de las cláusulas generales no obsta a su control judicial.", practicalEffects: ['En la práctica, este artículo rige control judicial de las cláusulas abusivas. La aprobación administrativa de las cláusulas generales no obsta a su control judicial.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['control', 'judicial', 'clusulas', 'abusivas', 'articulo 989'], segments: [], amendments: [] },
  { id: 'ccyc-art-990', lawId: 'codigo-civil-comercial', number: '990', order: 990, title: "Libertad de negociación", text: "Libertad de negociación. Las partes son libres para promover tratativas dirigidas a la formación del contrato, y para abandonarlas en cualquier momento.", plainLanguageExplanation: "Establece el régimen de libertad de negociación. Las partes son libres para promover tratativas dirigidas a la formación del contrato, y para abandonarlas en cualquier momento.", practicalEffects: ['En la práctica, este artículo rige libertad de negociación. Las partes son libres para promover tratativas dirigidas a la formación del contrato, y para abandonarlas en cualquier momento.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad', 'negociacin', 'articulo 990'], segments: [], amendments: [] },
  { id: 'ccyc-art-991', lawId: 'codigo-civil-comercial', number: '991', order: 991, title: "Deber de buena fe", text: "Deber de buena fe. Durante las tratativas preliminares, y aunque no se haya formulado una oferta, las partes deben obrar de buena fe para no frustrarlas injustificadamente. El incumplimiento de este deber genera la responsabilidad de resarcir el daño que sufra el afectado por haber confiado, sin su culpa, en la celebración del contrato.", plainLanguageExplanation: "Establece el régimen de deber de buena fe. Durante las tratativas preliminares, y aunque no se haya formulado una oferta, las partes deben obrar de buena fe para no frustrarlas injustificadamente.", practicalEffects: ['En la práctica, este artículo rige deber de buena fe. Durante las tratativas preliminares, y aunque no se haya formulado una oferta, las partes deben obrar de buena fe para no frustrarlas injustificadamente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deber', 'buena', 'articulo 991'], segments: [], amendments: [] },
  { id: 'ccyc-art-992', lawId: 'codigo-civil-comercial', number: '992', order: 992, title: "Deber de confidencialidad", text: "Deber de confidencialidad. Si durante las negociaciones, una de las partes facilita a la otra una información con carácter confidencial, el que la recibió tiene el deber de no revelarla y de no usarla inapropiadamente en su propio interés. La parte que incumple este deber queda obligada a reparar el daño sufrido por la otra y, si ha obtenido una ventaja indebida de la información confidencial, queda obligada a indemnizar a la otra parte en la medida de su propio enriquecimiento.", plainLanguageExplanation: "Establece el régimen de deber de confidencialidad. Si durante las negociaciones, una de las partes facilita a la otra una información con carácter confidencial, el que la recibió tiene el deber de no revelarla y de no usarla inapropiadamente en su propio interés.", practicalEffects: ['En la práctica, este artículo rige deber de confidencialidad. Si durante las negociaciones, una de las partes facilita a la otra una información con carácter confidencial, el que la recibió tiene el deber de no r'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deber', 'confidencialidad', 'articulo 992'], segments: [], amendments: [] },
  { id: 'ccyc-art-993', lawId: 'codigo-civil-comercial', number: '993', order: 993, title: "Cartas de intención", text: "Cartas de intención. Los instrumentos mediante los cuales una parte, o todas ellas, expresan un consentimiento para negociar sobre ciertas bases, limitado a cuestiones relativas a un futuro contrato, son de interpretación restrictiva. Sólo tienen la fuerza obligatoria de la oferta si cumplen sus requisitos. SECCION 4ª Contratos preliminares", plainLanguageExplanation: "Establece el régimen de cartas de intención. Los instrumentos mediante los cuales una parte, o todas ellas, expresan un consentimiento para negociar sobre ciertas bases, limitado a cuestiones relativas a un futuro contrato, son de interpretación restrictiva.", practicalEffects: ['En la práctica, este artículo rige cartas de intención. Los instrumentos mediante los cuales una parte, o todas ellas, expresan un consentimiento para negociar sobre ciertas bases, limitado a cuestiones rel'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cartas', 'intencin', 'articulo 993'], segments: [], amendments: [] },
  { id: 'ccyc-art-994', lawId: 'codigo-civil-comercial', number: '994', order: 994, title: "Disposiciones generales", text: "Disposiciones generales. Los contratos preliminares deben contener el acuerdo sobre los elementos esenciales particulares que identifiquen el contrato futuro definitivo. El plazo de vigencia de las promesas previstas en esta Sección es de un año, o el menor que convengan las partes, quienes pueden renovarlo a su vencimiento.", plainLanguageExplanation: "Establece el régimen de disposiciones generales. Los contratos preliminares deben contener el acuerdo sobre los elementos esenciales particulares que identifiquen el contrato futuro definitivo.", practicalEffects: ['En la práctica, este artículo rige disposiciones generales. Los contratos preliminares deben contener el acuerdo sobre los elementos esenciales particulares que identifiquen el contrato futuro definitivo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposiciones', 'generales', 'articulo 994'], segments: [], amendments: [] },
  { id: 'ccyc-art-995', lawId: 'codigo-civil-comercial', number: '995', order: 995, title: "Promesa de celebrar un contrato", text: "Promesa de celebrar un contrato. Las partes pueden pactar la obligación de celebrar un contrato futuro. El futuro contrato no puede ser de aquellos para los cuales se exige una forma bajo sanción de nulidad. Es aplicable el régimen de las obligaciones de hacer.", plainLanguageExplanation: "Establece el régimen de promesa de celebrar un contrato. Las partes pueden pactar la obligación de celebrar un contrato futuro.", practicalEffects: ['En la práctica, este artículo rige promesa de celebrar un contrato. Las partes pueden pactar la obligación de celebrar un contrato futuro.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['promesa', 'celebrar', 'contrato', 'articulo 995'], segments: [], amendments: [] },
  { id: 'ccyc-art-996', lawId: 'codigo-civil-comercial', number: '996', order: 996, title: "Contrato de opción", text: "Contrato de opción. El contrato que contiene una opción de concluir un contrato definitivo, otorga al beneficiario el derecho irrevocable de aceptarlo. Puede ser gratuito u oneroso, y debe observar la forma exigida para el contrato definitivo. No es transmisible a un tercero, excepto que así se lo estipule. SECCION 5ª Pacto de preferencia y contrato sujeto a conformidad", plainLanguageExplanation: "Establece el régimen de contrato de opción. El contrato que contiene una opción de concluir un contrato definitivo, otorga al beneficiario el derecho irrevocable de aceptarlo.", practicalEffects: ['En la práctica, este artículo rige contrato de opción. El contrato que contiene una opción de concluir un contrato definitivo, otorga al beneficiario el derecho irrevocable de aceptarlo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contrato', 'opcin', 'articulo 996'], segments: [], amendments: [] },
  { id: 'ccyc-art-997', lawId: 'codigo-civil-comercial', number: '997', order: 997, title: "Pacto de preferencia", text: "Pacto de preferencia. El pacto de preferencia genera una obligación de hacer a cargo de una de las partes, quien si decide celebrar un futuro contrato, debe hacerlo con la otra o las otras partes. Si se trata de participaciones sociales de cualquier naturaleza, de condominio, de partes en contratos asociativos o similares, el pacto puede ser recíproco. Los derechos y obligaciones derivados de este pacto son transmisibles a terceros con las modalidades que se estipulen.", plainLanguageExplanation: "Establece el régimen de pacto de preferencia. El pacto de preferencia genera una obligación de hacer a cargo de una de las partes, quien si decide celebrar un futuro contrato, debe hacerlo con la otra o las otras partes.", practicalEffects: ['En la práctica, este artículo rige pacto de preferencia. El pacto de preferencia genera una obligación de hacer a cargo de una de las partes, quien si decide celebrar un futuro contrato, debe hacerlo con la otra o las otras partes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pacto', 'preferencia', 'articulo 997'], segments: [], amendments: [] },
  { id: 'ccyc-art-998', lawId: 'codigo-civil-comercial', number: '998', order: 998, title: "Efectos", text: "Efectos. El otorgante de la preferencia debe dirigir a su o sus beneficiarios una declaración, con los requisitos de la oferta, comunicándole su decisión de celebrar el nuevo contrato, en su caso de conformidad con las estipulaciones del pacto. El contrato queda concluido con la aceptación del o de los beneficiarios.", plainLanguageExplanation: "Establece el régimen de efectos. El otorgante de la preferencia debe dirigir a su o sus beneficiarios una declaración, con los requisitos de la oferta, comunicándole su decisión de celebrar el nuevo contrato, en su caso de conformidad con las estipulaciones del pacto.", practicalEffects: ['En la práctica, este artículo rige efectos. El otorgante de la preferencia debe dirigir a su o sus beneficiarios una declaración, con los requisitos de la oferta, comunicándole su decisión de ce'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 998'], segments: [], amendments: [] },
  { id: 'ccyc-art-999', lawId: 'codigo-civil-comercial', number: '999', order: 999, title: "Contrato sujeto a conformidad", text: "Contrato sujeto a conformidad. El contrato cuyo perfeccionamiento depende de una conformidad o de una autorización queda sujeto a las reglas de la condición suspensiva. CAPITULO 4 Incapacidad e inhabilidad para contratar", plainLanguageExplanation: "Establece el régimen de contrato sujeto a conformidad. El contrato cuyo perfeccionamiento depende de una conformidad o de una autorización queda sujeto a las reglas de la condición suspensiva.", practicalEffects: ['En la práctica, este artículo rige contrato sujeto a conformidad. El contrato cuyo perfeccionamiento depende de una conformidad o de una autorización queda sujeto a las reglas de la condición suspensiva.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contrato', 'sujeto', 'conformidad', 'articulo 999'], segments: [], amendments: [] },
  { id: 'ccyc-art-1000', lawId: 'codigo-civil-comercial', number: '1000', order: 1000, title: "Efectos de la nulidad del contrato", text: "Efectos de la nulidad del contrato. Declarada la nulidad del contrato celebrado por la persona incapaz o con capacidad restringida, la parte capaz no tiene derecho para exigir la restitución o el reembolso de lo que ha pagado o gastado, excepto si el contrato enriqueció a la parte incapaz o con capacidad restringida y en cuanto se haya enriquecido.", plainLanguageExplanation: "Establece el régimen de efectos de la nulidad del contrato. Declarada la nulidad del contrato celebrado por la persona incapaz o con capacidad restringida, la parte capaz no tiene derecho para exigir la restitución o el reembolso de lo que ha pagado o gastado, excepto si el contrato enriqueció a la parte incapaz o con capacidad restringid", practicalEffects: ['En la práctica, este artículo rige efectos de la nulidad del contrato. Declarada la nulidad del contrato celebrado por la persona incapaz o con capacidad restringida, la parte capaz no tiene derecho para exigir la restitu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'nulidad', 'contrato', 'articulo 1000'], segments: [], amendments: [] },
  { id: 'ccyc-art-1001', lawId: 'codigo-civil-comercial', number: '1001', order: 1001, title: "Inhabilidades para contratar", text: "Inhabilidades para contratar. No pueden contratar, en interés propio o ajeno, según sea el caso, los que están impedidos para hacerlo conforme a disposiciones especiales. Los contratos cuya celebración está prohibida a determinados sujetos tampoco pueden ser otorgados por interpósita persona.", plainLanguageExplanation: "Establece el régimen de inhabilidades para contratar. No pueden contratar, en interés propio o ajeno, según sea el caso, los que están impedidos para hacerlo conforme a disposiciones especiales.", practicalEffects: ['En la práctica, este artículo rige inhabilidades para contratar. No pueden contratar, en interés propio o ajeno, según sea el caso, los que están impedidos para hacerlo conforme a disposiciones especiales.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inhabilidades', 'para', 'contratar', 'articulo 1001'], segments: [], amendments: [] },
  { id: 'ccyc-art-1002', lawId: 'codigo-civil-comercial', number: '1002', order: 1002, title: "Inhabilidades especiales", text: "Inhabilidades especiales. No pueden contratar en interés propio: a) los funcionarios públicos, respecto de bienes de cuya administración o enajenación están o han estado encargados; b) los jueces, funcionarios y auxiliares de la justicia, los árbitros y mediadores, y sus auxiliares, respecto de bienes relacionados con procesos en los que intervienen o han intervenido; c) los abogados y procuradores, respecto de bienes litigiosos en procesos en los que intervienen o han intervenido; d) los cónyuges, bajo el régimen de comunidad, entre sí. Los albaceas que no son herederos no pueden celebrar contrato de compraventa sobre los bienes de las testamentarias que estén a su cargo. CAPITULO 5 Objeto", plainLanguageExplanation: "Establece el régimen de inhabilidades especiales. No pueden contratar en interés propio: a) los funcionarios públicos, respecto de bienes de cuya administración o enajenación están o han estado encargados; b) los jueces, funcionarios y auxiliares de la justicia, los árbitros y mediadores, y sus auxiliares, respecto de bienes rel", practicalEffects: ['En la práctica, este artículo rige inhabilidades especiales. No pueden contratar en interés propio: a) los funcionarios públicos, respecto de bienes de cuya administración o enajenación están o han estado encarg'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inhabilidades', 'especiales', 'articulo 1002'], segments: [], amendments: [] },
  { id: 'ccyc-art-1003', lawId: 'codigo-civil-comercial', number: '1003', order: 1003, title: "Disposiciones generales", text: "Disposiciones generales. Se aplican al objeto del contrato las disposiciones de la Sección 1a, Capítulo 5, Título IV del Libro Primero de este Código. Debe ser lícito, posible, determinado o determinable, susceptible de valoración económica y corresponder a un interés de las partes, aun cuando éste no sea patrimonial.", plainLanguageExplanation: "Establece el régimen de disposiciones generales. Se aplican al objeto del contrato las disposiciones de la Sección 1a, Capítulo 5, Título IV del Libro Primero de este Código.", practicalEffects: ['En la práctica, este artículo rige disposiciones generales. Se aplican al objeto del contrato las disposiciones de la Sección 1a, Capítulo 5, Título IV del Libro Primero de este Código.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposiciones', 'generales', 'articulo 1003'], segments: [], amendments: [] },
  { id: 'ccyc-art-1004', lawId: 'codigo-civil-comercial', number: '1004', order: 1004, title: "Objetos prohibidos", text: "Objetos prohibidos. No pueden ser objeto de los contratos los hechos que son imposibles o están prohibidos por las leyes, son contrarios a la moral, al orden público, a la dignidad de la persona humana, o lesivos de los derechos ajenos; ni los bienes que por un motivo especial se prohíbe que lo sean. Cuando tengan por objeto derechos sobre el cuerpo humano se aplican los artículos 17 y 56.", plainLanguageExplanation: "Establece el régimen de objetos prohibidos. No pueden ser objeto de los contratos los hechos que son imposibles o están prohibidos por las leyes, son contrarios a la moral, al orden público, a la dignidad de la persona humana, o lesivos de los derechos ajenos; ni los bienes que por un motivo especial se prohíbe que lo sean.", practicalEffects: ['En la práctica, este artículo rige objetos prohibidos. No pueden ser objeto de los contratos los hechos que son imposibles o están prohibidos por las leyes, son contrarios a la moral, al orden público, a l'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['objetos', 'prohibidos', 'articulo 1004'], segments: [], amendments: [] },
  { id: 'ccyc-art-1005', lawId: 'codigo-civil-comercial', number: '1005', order: 1005, title: "Determinación", text: "Determinación. Cuando el objeto se refiere a bienes, éstos deben estar determinados en su especie o género según sea el caso, aunque no lo estén en su cantidad, si ésta puede ser determinada. Es determinable cuando se establecen los criterios suficientes para su individualización.", plainLanguageExplanation: "Establece el régimen de determinación. Cuando el objeto se refiere a bienes, éstos deben estar determinados en su especie o género según sea el caso, aunque no lo estén en su cantidad, si ésta puede ser determinada.", practicalEffects: ['En la práctica, este artículo rige determinación. Cuando el objeto se refiere a bienes, éstos deben estar determinados en su especie o género según sea el caso, aunque no lo estén en su cantidad, si ésta puede ser determinada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['determinacinarticulo 1005'], segments: [], amendments: [] },
  { id: 'ccyc-art-1006', lawId: 'codigo-civil-comercial', number: '1006', order: 1006, title: "Determinación por un tercero", text: "Determinación por un tercero. Las partes pueden pactar que la determinación del objeto sea efectuada por un tercero. En caso de que el tercero no realice la elección, sea imposible o no haya observado los criterios expresamente establecidos por las partes o por los usos y costumbres, puede recurrirse a la determinación judicial, petición que debe tramitar por el procedimiento más breve que prevea la legislación procesal.", plainLanguageExplanation: "Establece el régimen de determinación por un tercero. Las partes pueden pactar que la determinación del objeto sea efectuada por un tercero.", practicalEffects: ['En la práctica, este artículo rige determinación por un tercero. Las partes pueden pactar que la determinación del objeto sea efectuada por un tercero.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['determinacin', 'tercero', 'articulo 1006'], segments: [], amendments: [] },
  { id: 'ccyc-art-1007', lawId: 'codigo-civil-comercial', number: '1007', order: 1007, title: "Bienes existentes y futuros", text: "Bienes existentes y futuros. Los bienes futuros pueden ser objeto de los contratos. La promesa de transmitirlos está subordinada a la condición de que lleguen a existir, excepto que se trate de contratos aleatorios.", plainLanguageExplanation: "Establece el régimen de bienes existentes y futuros. Los bienes futuros pueden ser objeto de los contratos.", practicalEffects: ['En la práctica, este artículo rige bienes existentes y futuros. Los bienes futuros pueden ser objeto de los contratos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['bienes', 'existentes', 'futuros', 'articulo 1007'], segments: [], amendments: [] },
  { id: 'ccyc-art-1008', lawId: 'codigo-civil-comercial', number: '1008', order: 1008, title: "Bienes ajenos", text: "Bienes ajenos. Los bienes ajenos pueden ser objeto de los contratos. Si el que promete transmitirlos no ha garantizado el éxito de la promesa, sólo está obligado a emplear los medios necesarios para que la prestación se realice y, si por su culpa, el bien no se transmite, debe reparar los daños causados. Debe también indemnizarlos cuando ha garantizado la promesa y ésta no se cumple. El que ha contratado sobre bienes ajenos como propios es responsable de los daños si no hace entrega de ellos.", plainLanguageExplanation: "Establece el régimen de bienes ajenos. Los bienes ajenos pueden ser objeto de los contratos.", practicalEffects: ['En la práctica, este artículo rige bienes ajenos. Los bienes ajenos pueden ser objeto de los contratos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['bienes', 'ajenos', 'articulo 1008'], segments: [], amendments: [] },
  { id: 'ccyc-art-1009', lawId: 'codigo-civil-comercial', number: '1009', order: 1009, title: "Bienes litigiosos, gravados, o sujetos a medidas cautelares", text: "Bienes litigiosos, gravados, o sujetos a medidas cautelares. Los bienes litigiosos, gravados, o sujetos a medidas cautelares, pueden ser objeto de los contratos, sin perjuicio de los derechos de terceros. Quien de mala fe contrata sobre esos bienes como si estuviesen libres debe reparar los daños causados a la otra parte si ésta ha obrado de buena fe.", plainLanguageExplanation: "Establece el régimen de bienes litigiosos, gravados, o sujetos a medidas cautelares. Los bienes litigiosos, gravados, o sujetos a medidas cautelares, pueden ser objeto de los contratos, sin perjuicio de los derechos de terceros.", practicalEffects: ['En la práctica, este artículo rige bienes litigiosos, gravados, o sujetos a medidas cautelares. Los bienes litigiosos, gravados, o sujetos a medidas cautelares, pueden ser objeto de los contratos, sin perjuicio de los derechos de terceros.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['bienes', 'litigiosos', 'gravados', 'sujetos', 'medidas', 'cautelares', 'articulo 1009'], segments: [], amendments: [] },
  { id: 'ccyc-art-1010', lawId: 'codigo-civil-comercial', number: '1010', order: 1010, title: "Herencia futura", text: "Herencia futura. La herencia futura no puede ser objeto de los contratos ni tampoco pueden serlo los derechos hereditarios eventuales sobre objetos particulares, excepto lo dispuesto en el párrafo siguiente u otra disposición legal expresa. Los pactos relativos a una explotación productiva o a participaciones societarias de cualquier tipo, con miras a la conservación de la unidad de la gestión empresaria o a la prevención o solución de conflictos, pueden incluir disposiciones referidas a futuros derechos hereditarios y establecer compensaciones en favor de otros legitimarios. Estos pactos son válidos, sean o no parte el futuro causante y su cónyuge, si no afectan la legítima hereditaria, los derechos del cónyuge, ni los derechos de terceros.", plainLanguageExplanation: "Establece el régimen de herencia futura. La herencia futura no puede ser objeto de los contratos ni tampoco pueden serlo los derechos hereditarios eventuales sobre objetos particulares, excepto lo dispuesto en el párrafo siguiente u otra disposición legal expresa.", practicalEffects: ['En la práctica, este artículo rige herencia futura. La herencia futura no puede ser objeto de los contratos ni tampoco pueden serlo los derechos hereditarios eventuales sobre objetos particulares, excep'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['herencia', 'futura', 'articulo 1010'], segments: [], amendments: [] },
  { id: 'ccyc-art-1011', lawId: 'codigo-civil-comercial', number: '1011', order: 1011, title: "Contratos de larga duración", text: "Contratos de larga duración. En los contratos de larga duración el tiempo es esencial para el cumplimiento del objeto, de modo que se produzcan los efectos queridos por las partes o se satisfaga la necesidad que las indujo a contratar. Las partes deben ejercitar sus derechos conforme con un deber de colaboración, respetando la reciprocidad de las obligaciones del contrato, considerada en relación a la duración total. La parte que decide la rescisión debe dar a la otra la oportunidad razonable de renegociar de buena fe, sin incurrir en ejercicio abusivo de los derechos. CAPITULO 6 Causa", plainLanguageExplanation: "Establece el régimen de contratos de larga duración. En los contratos de larga duración el tiempo es esencial para el cumplimiento del objeto, de modo que se produzcan los efectos queridos por las partes o se satisfaga la necesidad que las indujo a contratar.", practicalEffects: ['En la práctica, este artículo rige contratos de larga duración. En los contratos de larga duración el tiempo es esencial para el cumplimiento del objeto, de modo que se produzcan los efectos queridos por las partes'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'larga', 'duracin', 'articulo 1011'], segments: [], amendments: [] },
  { id: 'ccyc-art-1012', lawId: 'codigo-civil-comercial', number: '1012', order: 1012, title: "Disposiciones generales", text: "Disposiciones generales. Se aplican a la causa de los contratos las disposiciones de la Sección 2ª, Capítulo 5, Título IV, Libro Primero de este Código.", plainLanguageExplanation: "Establece el régimen de disposiciones generales. Se aplican a la causa de los contratos las disposiciones de la Sección 2ª, Capítulo 5, Título IV, Libro Primero de este Código.", practicalEffects: ['En la práctica, este artículo rige disposiciones generales. Se aplican a la causa de los contratos las disposiciones de la Sección 2ª, Capítulo 5, Título IV, Libro Primero de este Código.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposiciones', 'generales', 'articulo 1012'], segments: [], amendments: [] },
  { id: 'ccyc-art-1013', lawId: 'codigo-civil-comercial', number: '1013', order: 1013, title: "Necesidad", text: "Necesidad. La causa debe existir en la formación del contrato y durante su celebración y subsistir durante su ejecución. La falta de causa da lugar, según los casos, a la nulidad, ade-cuación o extinción del contrato.", plainLanguageExplanation: "Establece el régimen de necesidad. La causa debe existir en la formación del contrato y durante su celebración y subsistir durante su ejecución.", practicalEffects: ['En la práctica, este artículo rige necesidad. La causa debe existir en la formación del contrato y durante su celebración y subsistir durante su ejecución.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['necesidadarticulo 1013'], segments: [], amendments: [] },
  { id: 'ccyc-art-1014', lawId: 'codigo-civil-comercial', number: '1014', order: 1014, title: "Causa ilícita", text: "Causa ilícita. El contrato es nulo cuando: a) su causa es contraria a la moral, al orden público o a las buenas costumbres; b) ambas partes lo han concluido por un motivo ilícito o inmoral común. Si sólo una de ellas ha obrado por un motivo ilícito o inmoral, no tiene derecho a invocar el contrato frente a la otra, pero ésta puede reclamar lo que ha dado, sin obligación de cumplir lo que ha ofrecido. CAPITULO 7 Forma", plainLanguageExplanation: "Establece el régimen de causa ilícita. El contrato es nulo cuando: a) su causa es contraria a la moral, al orden público o a las buenas costumbres; b) ambas partes lo han concluido por un motivo ilícito o inmoral común.", practicalEffects: ['En la práctica, este artículo rige causa ilícita. El contrato es nulo cuando: a) su causa es contraria a la moral, al orden público o a las buenas costumbres; b) ambas partes lo han concluido por un motivo ilícito o inmoral común.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['causa', 'ilcita', 'articulo 1014'], segments: [], amendments: [] },
  { id: 'ccyc-art-1015', lawId: 'codigo-civil-comercial', number: '1015', order: 1015, title: "Libertad de formas", text: "Libertad de formas. Sólo son formales los contratos a los cuales la ley les impone una forma determinada.", plainLanguageExplanation: "Establece el régimen de libertad de formas. Sólo son formales los contratos a los cuales la ley les impone una forma determinada.", practicalEffects: ['En la práctica, este artículo rige libertad de formas. Sólo son formales los contratos a los cuales la ley les impone una forma determinada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad', 'formas', 'articulo 1015'], segments: [], amendments: [] },
  { id: 'ccyc-art-1016', lawId: 'codigo-civil-comercial', number: '1016', order: 1016, title: "Modificaciones al contrato", text: "Modificaciones al contrato. La formalidad exigida para la celebración del contrato rige también para las modificaciones ulteriores que le sean introducidas, excepto que ellas versen solamente sobre estipulaciones accesorias o secundarias, o que exista disposición legal en contrario.", plainLanguageExplanation: "Establece el régimen de modificaciones al contrato. La formalidad exigida para la celebración del contrato rige también para las modificaciones ulteriores que le sean introducidas, excepto que ellas versen solamente sobre estipulaciones accesorias o secundarias, o que exista disposición legal en contrario.", practicalEffects: ['En la práctica, este artículo rige modificaciones al contrato. La formalidad exigida para la celebración del contrato rige también para las modificaciones ulteriores que le sean introducidas, excepto que ellas ver'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modificaciones', 'contrato', 'articulo 1016'], segments: [], amendments: [] },
  { id: 'ccyc-art-1017', lawId: 'codigo-civil-comercial', number: '1017', order: 1017, title: "Escritura pública", text: "Escritura pública. Deben ser otorgados por escritura pública: a) los contratos que tienen por objeto la adquisición, modificación o extinción de derechos reales sobre inmuebles. Quedan exceptuados los casos en que el acto es realizado mediante subasta proveniente de ejecución judicial o administrativa; b) los contratos que tienen por objeto derechos dudosos o litigiosos sobre inmuebles; c) todos los actos que sean accesorios de otros contratos otorgados en escritura pública; d) los demás contratos que, por acuerdo de partes o disposición de la ley, deben ser otorgados en escritura pública.", plainLanguageExplanation: "Establece el régimen de escritura pública. Deben ser otorgados por escritura pública: a) los contratos que tienen por objeto la adquisición, modificación o extinción de derechos reales sobre inmuebles.", practicalEffects: ['En la práctica, este artículo rige escritura pública. Deben ser otorgados por escritura pública: a) los contratos que tienen por objeto la adquisición, modificación o extinción de derechos reales sobre inmuebles.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['escritura', 'pblica', 'articulo 1017'], segments: [], amendments: [] },
  { id: 'ccyc-art-1018', lawId: 'codigo-civil-comercial', number: '1018', order: 1018, title: "Otorgamiento pendiente del instrumento", text: "Otorgamiento pendiente del instrumento. El otorgamiento pendiente de un instrumento previsto constituye una obligación de hacer si el futuro contrato no requiere una forma bajo sanción de nulidad. Si la parte condenada a otorgarlo es remisa, el juez lo hace en su representación, siempre que las contraprestaciones estén cumplidas, o sea asegurado su cumplimiento. CAPITULO 8 Prueba", plainLanguageExplanation: "Establece el régimen de otorgamiento pendiente del instrumento. El otorgamiento pendiente de un instrumento previsto constituye una obligación de hacer si el futuro contrato no requiere una forma bajo sanción de nulidad.", practicalEffects: ['En la práctica, este artículo rige otorgamiento pendiente del instrumento. El otorgamiento pendiente de un instrumento previsto constituye una obligación de hacer si el futuro contrato no requiere una forma bajo sanción de nulidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['otorgamiento', 'pendiente', 'instrumento', 'articulo 1018'], segments: [], amendments: [] },
  { id: 'ccyc-art-1019', lawId: 'codigo-civil-comercial', number: '1019', order: 1019, title: "Medios de prueba", text: "Medios de prueba. Los contratos pueden ser probados por todos los medios aptos para llegar a una razonable convicción según las reglas de la sana crítica, y con arreglo a lo que disponen las leyes procesales, excepto disposición legal que establezca un medio especial. Los contratos que sea de uso instrumentar no pueden ser probados exclusivamente por testigos.", plainLanguageExplanation: "Establece el régimen de medios de prueba. Los contratos pueden ser probados por todos los medios aptos para llegar a una razonable convicción según las reglas de la sana crítica, y con arreglo a lo que disponen las leyes procesales, excepto disposición legal que establezca un medio especial.", practicalEffects: ['En la práctica, este artículo rige medios de prueba. Los contratos pueden ser probados por todos los medios aptos para llegar a una razonable convicción según las reglas de la sana crítica, y con arreglo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medios', 'prueba', 'articulo 1019'], segments: [], amendments: [] },
  { id: 'ccyc-art-1020', lawId: 'codigo-civil-comercial', number: '1020', order: 1020, title: "Prueba de los contratos formales", text: "Prueba de los contratos formales. Los contratos en los cuales la formalidad es requerida a los fines probatorios pueden ser probados por otros medios, inclusive por testigos, si hay imposibilidad de obtener la prueba de haber sido cumplida la formalidad o si existe principio de prueba instrumental, o comienzo de ejecución. Se considera principio de prueba instrumental cualquier instrumento que emane de la otra parte, de su causante o de parte interesada en el asunto, que haga verosímil la existencia del contrato. CAPITULO 9 Efectos SECCION 1ª Efecto relativo", plainLanguageExplanation: "Establece el régimen de prueba de los contratos formales. Los contratos en los cuales la formalidad es requerida a los fines probatorios pueden ser probados por otros medios, inclusive por testigos, si hay imposibilidad de obtener la prueba de haber sido cumplida la formalidad o si existe principio de prueba instrumental, o comienzo de ejecución.", practicalEffects: ['En la práctica, este artículo rige prueba de los contratos formales. Los contratos en los cuales la formalidad es requerida a los fines probatorios pueden ser probados por otros medios, inclusive por testigos, si hay im'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prueba', 'contratos', 'formales', 'articulo 1020'], segments: [], amendments: [] },
  { id: 'ccyc-art-1021', lawId: 'codigo-civil-comercial', number: '1021', order: 1021, title: "Regla general", text: "Regla general. El contrato sólo tiene efecto entre las partes contratantes; no lo tiene con respecto a terceros, excepto en los casos previstos por la ley.", plainLanguageExplanation: "Establece el régimen de regla general. El contrato sólo tiene efecto entre las partes contratantes; no lo tiene con respecto a terceros, excepto en los casos previstos por la ley.", practicalEffects: ['En la práctica, este artículo rige regla general. El contrato sólo tiene efecto entre las partes contratantes; no lo tiene con respecto a terceros, excepto en los casos previstos por la ley.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['regla', 'general', 'articulo 1021'], segments: [], amendments: [] },
  { id: 'ccyc-art-1022', lawId: 'codigo-civil-comercial', number: '1022', order: 1022, title: "Situación de los terceros", text: "Situación de los terceros. El contrato no hace surgir obligaciones a cargo de terceros, ni los terceros tienen derecho a invocarlo para hacer recaer sobre las partes obligaciones que éstas no han convenido, excepto disposición legal.", plainLanguageExplanation: "Establece el régimen de situación de los terceros. El contrato no hace surgir obligaciones a cargo de terceros, ni los terceros tienen derecho a invocarlo para hacer recaer sobre las partes obligaciones que éstas no han convenido, excepto disposición legal.", practicalEffects: ['En la práctica, este artículo rige situación de los terceros. El contrato no hace surgir obligaciones a cargo de terceros, ni los terceros tienen derecho a invocarlo para hacer recaer sobre las partes obligacione'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['situacin', 'terceros', 'articulo 1022'], segments: [], amendments: [] },
  { id: 'ccyc-art-1023', lawId: 'codigo-civil-comercial', number: '1023', order: 1023, title: "Parte del contrato", text: "Parte del contrato. Se considera parte del contrato a quien: a) lo otorga a nombre propio, aunque lo haga en interés ajeno; b) es representado por un otorgante que actúa en su nombre e interés; c) manifiesta la voluntad contractual, aunque ésta sea transmitida por un corredor o por un agente sin representación.", plainLanguageExplanation: "Establece el régimen de parte del contrato. Se considera parte del contrato a quien: a) lo otorga a nombre propio, aunque lo haga en interés ajeno; b) es representado por un otorgante que actúa en su nombre e interés; c) manifiesta la voluntad contractual, aunque ésta sea transmitida por un corredor o por un agente sin rep", practicalEffects: ['En la práctica, este artículo rige parte del contrato. Se considera parte del contrato a quien: a) lo otorga a nombre propio, aunque lo haga en interés ajeno; b) es representado por un otorgante que actúa'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['parte', 'contrato', 'articulo 1023'], segments: [], amendments: [] },
  { id: 'ccyc-art-1024', lawId: 'codigo-civil-comercial', number: '1024', order: 1024, title: "Sucesores universales", text: "Sucesores universales. Los efectos del contrato se extienden, activa y pasivamente, a los sucesores universales, a no ser que las obligaciones que de él nacen sean inherentes a la persona, o que la transmisión sea incompatible con la naturaleza de la obligación, o esté prohibida por una cláusula del contrato o la ley. SECCION 2ª Incorporación de terceros al contrato", plainLanguageExplanation: "Establece el régimen de sucesores universales. Los efectos del contrato se extienden, activa y pasivamente, a los sucesores universales, a no ser que las obligaciones que de él nacen sean inherentes a la persona, o que la transmisión sea incompatible con la naturaleza de la obligación, o esté prohibida por una cláusula del contrato o la ley.", practicalEffects: ['En la práctica, este artículo rige sucesores universales. Los efectos del contrato se extienden, activa y pasivamente, a los sucesores universales, a no ser que las obligaciones que de él nacen sean inherente'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sucesores', 'universales', 'articulo 1024'], segments: [], amendments: [] },
  { id: 'ccyc-art-1025', lawId: 'codigo-civil-comercial', number: '1025', order: 1025, title: "Contratación a nombre de tercero", text: "Contratación a nombre de tercero. Quien contrata a nombre de un tercero sólo lo obliga si ejerce su representación. A falta de representación suficiente el contrato es ineficaz. La ratificación expresa o tácita del tercero suple la falta de representación; la ejecución implica ratificación tácita.", plainLanguageExplanation: "Establece el régimen de contratación a nombre de tercero. Quien contrata a nombre de un tercero sólo lo obliga si ejerce su representación.", practicalEffects: ['En la práctica, este artículo rige contratación a nombre de tercero. Quien contrata a nombre de un tercero sólo lo obliga si ejerce su representación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratacin', 'nombre', 'tercero', 'articulo 1025'], segments: [], amendments: [] },
  { id: 'ccyc-art-1026', lawId: 'codigo-civil-comercial', number: '1026', order: 1026, title: "Promesa del hecho de tercero", text: "Promesa del hecho de tercero. Quien promete el hecho de un tercero queda obligado a hacer lo razonablemente necesario para que el tercero acepte la promesa. Si ha garantizado que la promesa sea aceptada, queda obligado a obtenerla y responde personalmente en caso de negativa.", plainLanguageExplanation: "Establece el régimen de promesa del hecho de tercero. Quien promete el hecho de un tercero queda obligado a hacer lo razonablemente necesario para que el tercero acepte la promesa.", practicalEffects: ['En la práctica, este artículo rige promesa del hecho de tercero. Quien promete el hecho de un tercero queda obligado a hacer lo razonablemente necesario para que el tercero acepte la promesa.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['promesa', 'hecho', 'tercero', 'articulo 1026'], segments: [], amendments: [] },
  { id: 'ccyc-art-1027', lawId: 'codigo-civil-comercial', number: '1027', order: 1027, title: "Estipulación a favor de tercero", text: "Estipulación a favor de tercero. Si el contrato contiene una estipulación a favor de un tercero beneficiario, determinado o determinable, el promitente le confiere los derechos o facultades resultantes de lo que ha convenido con el estipulante. El estipulante puede revocar la estipulación mientras no reciba la aceptación del tercero beneficiario; pero no puede hacerlo sin la conformidad del promitente si éste tiene interés en que sea mantenida. El tercero aceptante obtiene directamente los derechos y las facultades resultantes de la estipulación a su favor. Las facultades del tercero beneficiario de aceptar la estipulación, y de prevalerse de ella luego de haberla aceptado, no se transmiten a sus herederos, excepto que haya cláusula expresa que lo autorice. La estipulación es de interpretación restrictiva.", plainLanguageExplanation: "Establece el régimen de estipulación a favor de tercero. Si el contrato contiene una estipulación a favor de un tercero beneficiario, determinado o determinable, el promitente le confiere los derechos o facultades resultantes de lo que ha convenido con el estipulante.", practicalEffects: ['En la práctica, este artículo rige estipulación a favor de tercero. Si el contrato contiene una estipulación a favor de un tercero beneficiario, determinado o determinable, el promitente le confiere los derechos o facu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['estipulacin', 'favor', 'tercero', 'articulo 1027'], segments: [], amendments: [] },
  { id: 'ccyc-art-1028', lawId: 'codigo-civil-comercial', number: '1028', order: 1028, title: "Relaciones entre las partes", text: "Relaciones entre las partes. El promitente puede oponer al tercero las defensas derivadas del contrato básico y las fundadas en otras relaciones con él. El estipulante puede: a) exigir al promitente el cumplimiento de la prestación, sea a favor del tercer beneficiario aceptante, sea a su favor si el tercero no la aceptó o el estipulante la revocó; b) resolver el contrato en caso de incumplimiento, sin perjuicio de los derechos del tercero beneficiario.", plainLanguageExplanation: "Establece el régimen de relaciones entre las partes. El promitente puede oponer al tercero las defensas derivadas del contrato básico y las fundadas en otras relaciones con él.", practicalEffects: ['En la práctica, este artículo rige relaciones entre las partes. El promitente puede oponer al tercero las defensas derivadas del contrato básico y las fundadas en otras relaciones con él.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['relaciones', 'entre', 'partes', 'articulo 1028'], segments: [], amendments: [] },
  { id: 'ccyc-art-1029', lawId: 'codigo-civil-comercial', number: '1029', order: 1029, title: "Contrato para persona a designar", text: "Contrato para persona a designar. Cualquier parte puede reservarse la facultad de designar ulteriormente a un tercero para que asuma su posición contractual, excepto si el contrato no puede ser celebrado por medio de representante, o la determinación de los sujetos es indispensable. La asunción de la posición contractual se produce con efectos retroactivos a la fecha del contrato, cuando el tercero acepta la nominación y su aceptación es comunicada a la parte que no hizo la reserva. Esta comunicación debe revestir la misma forma que el contrato, y ser efectuada dentro del plazo estipulado o, en su defecto, dentro de los quince días desde su celebración. Mientras no haya una aceptación del tercero, el contrato produce efectos entre las partes.", plainLanguageExplanation: "Establece el régimen de contrato para persona a designar. Cualquier parte puede reservarse la facultad de designar ulteriormente a un tercero para que asuma su posición contractual, excepto si el contrato no puede ser celebrado por medio de representante, o la determinación de los sujetos es indispensable.", practicalEffects: ['En la práctica, este artículo rige contrato para persona a designar. Cualquier parte puede reservarse la facultad de designar ulteriormente a un tercero para que asuma su posición contractual, excepto si el contrato no'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contrato', 'para', 'persona', 'designar', 'articulo 1029'], segments: [], amendments: [] },
  { id: 'ccyc-art-1030', lawId: 'codigo-civil-comercial', number: '1030', order: 1030, title: "Contrato por cuenta de quien corresponda", text: "Contrato por cuenta de quien corresponda. El contrato celebrado por cuenta de quien corresponda queda sujeto a las reglas de la condición suspensiva. El tercero asume la posición contractual cuando se produce el hecho que lo determina como beneficiario del contrato. SECCION 3ª Suspensión del cumplimiento y fuerza mayor", plainLanguageExplanation: "Establece el régimen de contrato por cuenta de quien corresponda. El contrato celebrado por cuenta de quien corresponda queda sujeto a las reglas de la condición suspensiva.", practicalEffects: ['En la práctica, este artículo rige contrato por cuenta de quien corresponda. El contrato celebrado por cuenta de quien corresponda queda sujeto a las reglas de la condición suspensiva.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contrato', 'cuenta', 'quien', 'corresponda', 'articulo 1030'], segments: [], amendments: [] },
  { id: 'ccyc-art-1031', lawId: 'codigo-civil-comercial', number: '1031', order: 1031, title: "Suspensión del cumplimiento", text: "Suspensión del cumplimiento. En los contratos bilaterales, cuando las partes deben cumplir simultáneamente, una de ellas puede suspender el cumplimiento de la prestación, hasta que la otra cumpla u ofrezca cumplir. La suspensión puede ser deducida judicialmente como acción o como excepción. Si la prestación es a favor de varios interesados, puede suspenderse la parte debida a cada uno hasta la ejecución completa de la contraprestación.", plainLanguageExplanation: "Establece el régimen de suspensión del cumplimiento. En los contratos bilaterales, cuando las partes deben cumplir simultáneamente, una de ellas puede suspender el cumplimiento de la prestación, hasta que la otra cumpla u ofrezca cumplir.", practicalEffects: ['En la práctica, este artículo rige suspensión del cumplimiento. En los contratos bilaterales, cuando las partes deben cumplir simultáneamente, una de ellas puede suspender el cumplimiento de la prestación, hasta que la otra cumpla u ofrezca cumplir.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensin', 'cumplimiento', 'articulo 1031'], segments: [], amendments: [] },
  { id: 'ccyc-art-1032', lawId: 'codigo-civil-comercial', number: '1032', order: 1032, title: "Tutela preventiva", text: "Tutela preventiva. Una parte puede suspender su propio cumplimiento si sus derechos sufriesen una grave amenaza de daño porque la otra parte ha sufrido un menoscabo significativo en su aptitud para cumplir, o en su solvencia. La suspensión queda sin efecto cuando la otra parte cumple o da seguridades suficientes de que el cumplimiento será realizado. SECCION 4ª Obligación de saneamiento Parágrafo 1° Disposiciones generales", plainLanguageExplanation: "Establece el régimen de tutela preventiva. Una parte puede suspender su propio cumplimiento si sus derechos sufriesen una grave amenaza de daño porque la otra parte ha sufrido un menoscabo significativo en su aptitud para cumplir, o en su solvencia.", practicalEffects: ['En la práctica, este artículo rige tutela preventiva. Una parte puede suspender su propio cumplimiento si sus derechos sufriesen una grave amenaza de daño porque la otra parte ha sufrido un menoscabo sign'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tutela', 'preventiva', 'articulo 1032'], segments: [], amendments: [] },
  { id: 'ccyc-art-1033', lawId: 'codigo-civil-comercial', number: '1033', order: 1033, title: "Sujetos responsables", text: "Sujetos responsables. Están obligados al saneamiento: a) el transmitente de bienes a título oneroso; b) quien ha dividido bienes con otros; c) sus respectivos antecesores, si han efectuado la correspondiente transferencia a título oneroso.", plainLanguageExplanation: "Establece el régimen de sujetos responsables. Están obligados al saneamiento: a) el transmitente de bienes a título oneroso; b) quien ha dividido bienes con otros; c) sus respectivos antecesores, si han efectuado la correspondiente transferencia a título oneroso.", practicalEffects: ['En la práctica, este artículo rige sujetos responsables. Están obligados al saneamiento: a) el transmitente de bienes a título oneroso; b) quien ha dividido bienes con otros; c) sus respectivos antecesores,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sujetos', 'responsables', 'articulo 1033'], segments: [], amendments: [] },
  { id: 'ccyc-art-1034', lawId: 'codigo-civil-comercial', number: '1034', order: 1034, title: "Garantías comprendidas en la obligación de saneamiento", text: "Garantías comprendidas en la obligación de saneamiento. El obligado al saneamiento garantiza por evicción y por vicios ocultos conforme a lo dispuesto en esta Sección, sin perjuicio de las normas especiales.", plainLanguageExplanation: "Establece el régimen de garantías comprendidas en la obligación de saneamiento. El obligado al saneamiento garantiza por evicción y por vicios ocultos conforme a lo dispuesto en esta Sección, sin perjuicio de las normas especiales.", practicalEffects: ['En la práctica, este artículo rige garantías comprendidas en la obligación de saneamiento. El obligado al saneamiento garantiza por evicción y por vicios ocultos conforme a lo dispuesto en esta Sección, sin perjuicio de las normas especiales'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garantas', 'comprendidas', 'obligacin', 'saneamiento', 'articulo 1034'], segments: [], amendments: [] },
  { id: 'ccyc-art-1035', lawId: 'codigo-civil-comercial', number: '1035', order: 1035, title: "Adquisición a título gratuito", text: "Adquisición a título gratuito. El adquirente a título gratuito puede ejercer en su provecho las acciones de responsabilidad por saneamiento correspondientes a sus antecesores.", plainLanguageExplanation: "Establece el régimen de adquisición a título gratuito. El adquirente a título gratuito puede ejercer en su provecho las acciones de responsabilidad por saneamiento correspondientes a sus antecesores.", practicalEffects: ['En la práctica, este artículo rige adquisición a título gratuito. El adquirente a título gratuito puede ejercer en su provecho las acciones de responsabilidad por saneamiento correspondientes a sus antecesores.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['adquisicin', 'ttulo', 'gratuito', 'articulo 1035'], segments: [], amendments: [] },
  { id: 'ccyc-art-1036', lawId: 'codigo-civil-comercial', number: '1036', order: 1036, title: "Disponibilidad", text: "Disponibilidad. La responsabilidad por saneamiento existe aunque no haya sido estipulada por las partes. Estas pueden aumentarla, disminuirla o suprimirla, sin perjuicio de lo dispuesto en el artículo siguiente.", plainLanguageExplanation: "Establece el régimen de disponibilidad. La responsabilidad por saneamiento existe aunque no haya sido estipulada por las partes.", practicalEffects: ['En la práctica, este artículo rige disponibilidad. La responsabilidad por saneamiento existe aunque no haya sido estipulada por las partes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disponibilidadarticulo 1036'], segments: [], amendments: [] },
  { id: 'ccyc-art-1037', lawId: 'codigo-civil-comercial', number: '1037', order: 1037, title: "Interpretación de la supresión y de la disminución de la responsabilidad por saneamiento", text: "Interpretación de la supresión y de la disminución de la responsabilidad por saneamiento. Las cláusulas de supresión y disminución de la responsabilidad por saneamiento son de interpretación restrictiva.", plainLanguageExplanation: "Establece el régimen de interpretación de la supresión y de la disminución de la responsabilidad por saneamiento. Las cláusulas de supresión y disminución de la responsabilidad por saneamiento son de interpretación restrictiva.", practicalEffects: ['En la práctica, este artículo rige interpretación de la supresión y de la disminución de la responsabilidad por saneamiento. Las cláusulas de supresión y disminución de la responsabilidad por saneamiento son de interpretación restrictiva.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['interpretacin', 'supresin', 'disminucin', 'responsabilidad', 'saneamiento', 'articulo 1037'], segments: [], amendments: [] },
  { id: 'ccyc-art-1038', lawId: 'codigo-civil-comercial', number: '1038', order: 1038, title: "Casos en los que se las tiene por no convenidas", text: "Casos en los que se las tiene por no convenidas. La supresión y la disminución de la responsabilidad por saneamiento se tienen por no convenidas en los siguientes casos: a) si el enajenante conoció, o debió conocer el peligro de evicción, o la existencia de vicios; b) si el enajenante actúa profesionalmente en la actividad a la que corresponde la enajenación, a menos que el adquirente también se desempeñe profesionalmente en esa actividad.", plainLanguageExplanation: "Establece el régimen de casos en los que se las tiene por no convenidas. La supresión y la disminución de la responsabilidad por saneamiento se tienen por no convenidas en los siguientes casos: a) si el enajenante conoció, o debió conocer el peligro de evicción, o la existencia de vicios; b) si el enajenante actúa profesionalmente en la actividad a la", practicalEffects: ['En la práctica, este artículo rige casos en los que se las tiene por no convenidas. La supresión y la disminución de la responsabilidad por saneamiento se tienen por no convenidas en los siguientes casos: a) si el enajenante conoció,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'tiene', 'convenidas', 'articulo 1038'], segments: [], amendments: [] },
  { id: 'ccyc-art-1039', lawId: 'codigo-civil-comercial', number: '1039', order: 1039, title: "Responsabilidad por saneamiento", text: "Responsabilidad por saneamiento. El acreedor de la obligación de saneamiento tiene derecho a optar entre: a) reclamar el saneamiento del título o la subsanación de los vicios; b) reclamar un bien equivalente, si es fungible; c) declarar la resolución del contrato, excepto en los casos previstos por los artículos 1050 y 1057.", plainLanguageExplanation: "Establece el régimen de responsabilidad por saneamiento. El acreedor de la obligación de saneamiento tiene derecho a optar entre: a) reclamar el saneamiento del título o la subsanación de los vicios; b) reclamar un bien equivalente, si es fungible; c) declarar la resolución del contrato, excepto en los casos previstos por los artículos", practicalEffects: ['En la práctica, este artículo rige responsabilidad por saneamiento. El acreedor de la obligación de saneamiento tiene derecho a optar entre: a) reclamar el saneamiento del título o la subsanación de los vicios; b) recl'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'saneamiento', 'articulo 1039'], segments: [], amendments: [] },
  { id: 'ccyc-art-1040', lawId: 'codigo-civil-comercial', number: '1040', order: 1040, title: "Responsabilidad por daños", text: "Responsabilidad por daños. El acreedor de la obligación de saneamiento también tiene derecho a la reparación de los daños en los casos previstos en el artículo 1039, excepto: a) si el adquirente conoció, o pudo conocer el peligro de la evicción o la existencia de vicios; b) si el enajenante no conoció, ni pudo conocer el peligro de la evicción o la existencia de vicios; c) si la transmisión fue hecha a riesgo del adquirente; d) si la adquisición resulta de una subasta judicial o administrativa. La exención de responsabilidad por daños prevista en los incisos a) y b) no puede invocarse por el enajenante que actúa profesionalmente en la actividad a la que corresponde la enajenación, a menos que el adquirente también se desempeñe profesionalmente en esa actividad.", plainLanguageExplanation: "Establece el régimen de responsabilidad por daños. El acreedor de la obligación de saneamiento también tiene derecho a la reparación de los daños en los casos previstos en el artículo 1039, excepto: a) si el adquirente conoció, o pudo conocer el peligro de la evicción o la existencia de vicios; b) si el enajenante no conoció, ni", practicalEffects: ['En la práctica, este artículo rige responsabilidad por daños. El acreedor de la obligación de saneamiento también tiene derecho a la reparación de los daños en los casos previstos en el artículo 1039, excepto: a)'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'daos', 'articulo 1040'], segments: [], amendments: [] },
  { id: 'ccyc-art-1041', lawId: 'codigo-civil-comercial', number: '1041', order: 1041, title: "Pluralidad de bienes", text: "Pluralidad de bienes. En los casos en que la responsabilidad por saneamiento resulta de la enajenación de varios bienes se aplican las siguientes reglas: a) si fueron enajenados como conjunto, es indivisible; b) si fueron enajenados separadamente, es divisible, aunque haya habido una contraprestación única. En su caso, rigen las disposiciones aplicables a las cosas accesorias.", plainLanguageExplanation: "Establece el régimen de pluralidad de bienes. En los casos en que la responsabilidad por saneamiento resulta de la enajenación de varios bienes se aplican las siguientes reglas: a) si fueron enajenados como conjunto, es indivisible; b) si fueron enajenados separadamente, es divisible, aunque haya habido una contraprestación única.", practicalEffects: ['En la práctica, este artículo rige pluralidad de bienes. En los casos en que la responsabilidad por saneamiento resulta de la enajenación de varios bienes se aplican las siguientes reglas: a) si fueron enaje'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pluralidad', 'bienes', 'articulo 1041'], segments: [], amendments: [] },
  { id: 'ccyc-art-1042', lawId: 'codigo-civil-comercial', number: '1042', order: 1042, title: "Pluralidad de sujetos", text: "Pluralidad de sujetos. Quienes tienen responsabilidad por saneamiento en virtud de enajenaciones sucesivas son obligados concurrentes. Si el bien ha sido enajenado simultáneamente por varios copropietarios, éstos sólo responden en proporción a su cuota parte indivisa, excepto que se haya pactado su solidaridad.", plainLanguageExplanation: "Establece el régimen de pluralidad de sujetos. Quienes tienen responsabilidad por saneamiento en virtud de enajenaciones sucesivas son obligados concurrentes.", practicalEffects: ['En la práctica, este artículo rige pluralidad de sujetos. Quienes tienen responsabilidad por saneamiento en virtud de enajenaciones sucesivas son obligados concurrentes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pluralidad', 'sujetos', 'articulo 1042'], segments: [], amendments: [] },
  { id: 'ccyc-art-1043', lawId: 'codigo-civil-comercial', number: '1043', order: 1043, title: "Ignorancia o error", text: "Ignorancia o error. El obligado al saneamiento no puede invocar su ignorancia o error, excepto estipulación en contrario. Parágrafo 2° Responsabilidad por evicción", plainLanguageExplanation: "Establece el régimen de ignorancia o error. El obligado al saneamiento no puede invocar su ignorancia o error, excepto estipulación en contrario.", practicalEffects: ['En la práctica, este artículo rige ignorancia o error. El obligado al saneamiento no puede invocar su ignorancia o error, excepto estipulación en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ignorancia', 'error', 'articulo 1043'], segments: [], amendments: [] },
  { id: 'ccyc-art-1044', lawId: 'codigo-civil-comercial', number: '1044', order: 1044, title: "Contenido de la responsabilidad por evicción", text: "Contenido de la responsabilidad por evicción. La responsabilidad por evicción asegura la existencia y la legitimidad del derecho transmitido, y se extiende a: a) toda turbación de derecho, total o parcial, que recae sobre el bien, por causa anterior o contemporánea a la adquisición; b) los reclamos de terceros fundados en derechos resultantes de la propiedad intelectual o industrial, excepto si el enajenante se ajustó a especificaciones suministradas por el adquirente; c) las turbaciones de hecho causadas por el transmitente.", plainLanguageExplanation: "Establece el régimen de contenido de la responsabilidad por evicción. La responsabilidad por evicción asegura la existencia y la legitimidad del derecho transmitido, y se extiende a: a) toda turbación de derecho, total o parcial, que recae sobre el bien, por causa anterior o contemporánea a la adquisición; b) los reclamos de terceros fundados en de", practicalEffects: ['En la práctica, este artículo rige contenido de la responsabilidad por evicción. La responsabilidad por evicción asegura la existencia y la legitimidad del derecho transmitido, y se extiende a: a) toda turbación de derecho, total o'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contenido', 'responsabilidad', 'eviccin', 'articulo 1044'], segments: [], amendments: [] },
  { id: 'ccyc-art-1045', lawId: 'codigo-civil-comercial', number: '1045', order: 1045, title: "Exclusiones", text: "Exclusiones. La responsabilidad por evicción no comprende: a) las turbaciones de hecho causadas por terceros ajenos al transmitente; b) las turbaciones de derecho provenientes de una disposición legal; c) la evicción resultante de un derecho de origen anterior a la transferencia, y consolidado posteriormente. Sin embargo, el tribunal puede apartarse de esta disposición si hay un desequilibrio económico desproporcionado.", plainLanguageExplanation: "Establece el régimen de exclusiones. La responsabilidad por evicción no comprende: a) las turbaciones de hecho causadas por terceros ajenos al transmitente; b) las turbaciones de derecho provenientes de una disposición legal; c) la evicción resultante de un derecho de origen anterior a la transferencia, y consolidado posteriormente.", practicalEffects: ['En la práctica, este artículo rige exclusiones. La responsabilidad por evicción no comprende: a) las turbaciones de hecho causadas por terceros ajenos al transmitente; b) las turbaciones de derecho'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['exclusionesarticulo 1045'], segments: [], amendments: [] },
  { id: 'ccyc-art-1046', lawId: 'codigo-civil-comercial', number: '1046', order: 1046, title: "Citación por evicción", text: "Citación por evicción. Si un tercero demanda al adquirente en un proceso del que pueda resultar la evicción de la cosa, el garante citado a juicio debe comparecer en los términos de la ley de procedimientos. El adquirente puede seguir actuando en el proceso.", plainLanguageExplanation: "Establece el régimen de citación por evicción. Si un tercero demanda al adquirente en un proceso del que pueda resultar la evicción de la cosa, el garante citado a juicio debe comparecer en los términos de la ley de procedimientos.", practicalEffects: ['En la práctica, este artículo rige citación por evicción. Si un tercero demanda al adquirente en un proceso del que pueda resultar la evicción de la cosa, el garante citado a juicio debe comparecer en los términos de la ley de procedimientos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['citacin', 'eviccin', 'articulo 1046'], segments: [], amendments: [] },
  { id: 'ccyc-art-1047', lawId: 'codigo-civil-comercial', number: '1047', order: 1047, title: "Gastos de defensa", text: "Gastos de defensa. El garante debe pagar al adquirente los gastos que éste ha afrontado para la defensa de sus derechos. Sin embargo, el adquirente no puede cobrarlos, ni efectuar ningún otro reclamo si: a) no citó al garante al proceso; b) citó al garante, y aunque éste se allanó, continuó con la defensa y fue vencido.", plainLanguageExplanation: "Establece el régimen de gastos de defensa. El garante debe pagar al adquirente los gastos que éste ha afrontado para la defensa de sus derechos.", practicalEffects: ['En la práctica, este artículo rige gastos de defensa. El garante debe pagar al adquirente los gastos que éste ha afrontado para la defensa de sus derechos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gastos', 'defensa', 'articulo 1047'], segments: [], amendments: [] },
  { id: 'ccyc-art-1048', lawId: 'codigo-civil-comercial', number: '1048', order: 1048, title: "Cesación de la responsabilidad", text: "Cesación de la responsabilidad. En los casos en que se promueve el proceso judicial, la responsabilidad por evicción cesa: a) si el adquirente no cita al garante, o lo hace después de vencido el plazo que establece la ley procesal; b) si el garante no comparece al proceso judicial, y el adquirente, actuando de mala fe, no opone las defensas pertinentes, no las sostiene, o no interpone o no prosigue los recursos ordinarios de que dispone contra el fallo desfavorable; c) si el adquirente se allana a la demanda sin la conformidad del garante; o somete la cuestión a arbitraje y el laudo le es desfavorable. Sin embargo, la responsabilidad subsiste si el adquirente prueba que, por no haber existido oposición justa que hacer al derecho del vencedor, la citación oportuna del garante por evicción, o la interposición o sustanciación de los recursos, eran inútiles; o que el allanamiento o el laudo desfavorable son ajustados a derecho.", plainLanguageExplanation: "Establece el régimen de cesación de la responsabilidad. En los casos en que se promueve el proceso judicial, la responsabilidad por evicción cesa: a) si el adquirente no cita al garante, o lo hace después de vencido el plazo que establece la ley procesal; b) si el garante no comparece al proceso judicial, y el adquirente, actuando de", practicalEffects: ['En la práctica, este artículo rige cesación de la responsabilidad. En los casos en que se promueve el proceso judicial, la responsabilidad por evicción cesa: a) si el adquirente no cita al garante, o lo hace después d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cesacin', 'responsabilidad', 'articulo 1048'], segments: [], amendments: [] },
  { id: 'ccyc-art-1049', lawId: 'codigo-civil-comercial', number: '1049', order: 1049, title: "Régimen de las acciones", text: "Régimen de las acciones. El acreedor de la responsabilidad dispone del derecho a declarar la resolución: a) si los defectos en el título afectan el valor del bien a tal extremo que, de haberlos conocido, el adquirente no lo habría adquirido, o su contraprestación habría sido significativamente menor; b) si una sentencia o un laudo produce la evicción.", plainLanguageExplanation: "Establece el régimen de régimen de las acciones. El acreedor de la responsabilidad dispone del derecho a declarar la resolución: a) si los defectos en el título afectan el valor del bien a tal extremo que, de haberlos conocido, el adquirente no lo habría adquirido, o su contraprestación habría sido significativamente menor; b)", practicalEffects: ['En la práctica, este artículo rige régimen de las acciones. El acreedor de la responsabilidad dispone del derecho a declarar la resolución: a) si los defectos en el título afectan el valor del bien a tal extrem'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rgimen', 'acciones', 'articulo 1049'], segments: [], amendments: [] },
  { id: 'ccyc-art-1050', lawId: 'codigo-civil-comercial', number: '1050', order: 1050, title: "Prescripción adquisitiva", text: "Prescripción adquisitiva. Cuando el derecho del adquirente se sanea por el transcurso del plazo de prescripción adquisitiva, se extingue la responsabilidad por evicción. Parágrafo 3° Responsabilidad por vicios ocultos", plainLanguageExplanation: "Establece el régimen de prescripción adquisitiva. Cuando el derecho del adquirente se sanea por el transcurso del plazo de prescripción adquisitiva, se extingue la responsabilidad por evicción.", practicalEffects: ['En la práctica, este artículo rige prescripción adquisitiva. Cuando el derecho del adquirente se sanea por el transcurso del plazo de prescripción adquisitiva, se extingue la responsabilidad por evicción.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prescripcin', 'adquisitiva', 'articulo 1050'], segments: [], amendments: [] },
];
